  'sleep.ex4': {'en': 'No intense workouts within 2 hours of bed — keep it gentle.', 'ru': 'Никаких интенсивных тренировок за 2 часа до сна — только лёгкое.', 'uk': 'Жодних інтенсивних тренувань за 2 години до сну — лише легке.'},
  'sleep.nu1': {'en': 'Avoid caffeine after 3 p.m. (coffee, strong tea, energy drinks).', 'ru': 'Без кофеина после 15:00 (кофе, крепкий чай, энергетики).', 'uk': 'Без кофеїну після 15:00 (кава, міцний чай, енергетики).'},
  'sleep.nu2': {'en': 'Have your last meal 2-3 hours before sleep, keep it light.', 'ru': 'Последний приём пищи за 2–3 часа до сна, лёгкий.', 'uk': 'Останній прийом їжі за 2–3 години до сну, легкий.'},
  'sleep.nu3': {'en': 'Warm milk or herbal tea and a few nuts (magnesium) can help.', 'ru': 'Тёплое молоко или травяной чай и немного орехов (магний) помогают.', 'uk': 'Тепле молоко або трав’яний чай і трохи горіхів (магній) допомагають.'},
