  'diet.homeTitle': {'en': "Today's movement", 'ru': 'Движение сегодня', 'uk': 'Рух сьогодні'},
  'diet.homeDesk': {'en': 'Desk job? Fit movement around it — no gym needed.', 'ru': 'Сидячая работа? Двигайтесь вокруг неё — зал не нужен.', 'uk': 'Сидяча робота? Рухайтеся навколо неї — зал не потрібен.'},
  'diet.homeActive': {'en': 'Keep the balance of cardio and strength through the week.', 'ru': 'Держите баланс кардио и силовых в течение недели.', 'uk': 'Тримайте баланс кардіо та силових протягом тижня.'},
  'diet.morning': {'en': 'Morning: 5-10 min charge — squats, plank, arm swings right after waking.', 'ru': 'Утро: 5–10 мин зарядка — приседания, планка, махи руками сразу после пробуждения.', 'uk': 'Ранок: 5–10 хв зарядка — присідання, планка, махи руками одразу після пробудження.'},
  'diet.evening': {'en': 'Evening: 15-20 min home set — push-ups, lunges, core, then stretching.', 'ru': 'Вечер: 15–20 мин дома — отжимания, выпады, пресс, затем растяжка.', 'uk': 'Вечір: 15–20 хв удома — віджимання, випади, прес, потім розтяжка.'},
  'diet.cardio': {'en': 'Running: start with 20-30 min at a pace you can talk at, 2-3x a week; grow slowly.', 'ru': 'Бег: начните с 20–30 мин в темпе, когда можете говорить, 2–3 раза в неделю; наращивайте постепенно.', 'uk': 'Біг: почніть з 20–30 хв у темпі, коли можете говорити, 2–3 рази на тиждень; нарощуйте поступово.'},
  'diet.injury': {'en': 'Injuries: warm up first, avoid pain, skip loading the hurt area — swap in swimming or cycling.', 'ru': 'Травмы: сначала разминка, избегайте боли, не нагружайте больное место — замените плаванием или велосипедом.', 'uk': 'Травми: спершу розминка, уникайте болю, не навантажуйте хворе місце — замініть плаванням або велосипедом.'},
  'diet.recommendedTitle': {'en': 'Diets for you', 'ru': 'Диеты для вас', 'uk': 'Дієти для вас'},
  'diet.recommended': {'en': 'Recommended', 'ru': 'Рекомендуем', 'uk': 'Рекомендуємо'},
  'diet.plan.mediterranean.name': {'en': 'Mediterranean', 'ru': 'Средиземноморская', 'uk': 'Середземноморська'},
  'diet.plan.mediterranean.summary': {'en': 'Vegetables, fish, olive oil, whole grains and nuts. Heart-healthy and easy to keep long term.', 'ru': 'Овощи, рыба, оливковое масло, цельные злаки и орехи. Полезна для сердца и легко соблюдать долго.', 'uk': 'Овочі, риба, оливкова олія, цільні злаки та горіхи. Корисна для серця і легко дотримуватися довго.'},
  'diet.plan.mediterranean.tips': {'en': 'Fish 2-3x a week, olive oil instead of butter, a handful of nuts a day.', 'ru': 'Рыба 2–3 раза в неделю, оливковое масло вместо сливочного, горсть орехов в день.', 'uk': 'Риба 2–3 рази на тиждень, оливкова олія замість вершкового, жменя горіхів на день.'},
  'diet.plan.dash.name': {'en': 'DASH', 'ru': 'DASH', 'uk': 'DASH'},
  'diet.plan.dash.summary': {'en': 'Designed to lower blood pressure: rich in vegetables, fruit and low-fat dairy, low in salt.', 'ru': 'Создана для снижения давления: много овощей, фруктов и нежирных молочных, мало соли.', 'uk': 'Створена для зниження тиску: багато овочів, фруктів і нежирних молочних, мало солі.'},
  'diet.plan.dash.tips': {'en': 'Cut added salt, add a fruit and a vegetable to every meal.', 'ru': 'Уменьшите соль, добавляйте фрукт и овощ к каждому приёму пищи.', 'uk': 'Зменшіть сіль, додавайте фрукт і овоч до кожного прийому їжі.'},
  'diet.plan.balanced.name': {'en': 'Balanced plate', 'ru': 'Сбалансированная тарелка', 'uk': 'Збалансована тарілка'},
  'diet.plan.balanced.summary': {'en': 'Half the plate vegetables, a quarter protein, a quarter whole-grain carbs. Simple and flexible.', 'ru': 'Половина тарелки — овощи, четверть — белок, четверть — цельные углеводы. Просто и гибко.', 'uk': 'Половина тарілки — овочі, чверть — білок, чверть — цільні вуглеводи. Просто й гнучко.'},
  'diet.plan.balanced.tips': {'en': 'Use the plate rule at each meal; no foods are banned, just portions.', 'ru': 'Правило тарелки на каждый приём; ничего не запрещено, важны порции.', 'uk': 'Правило тарілки на кожен прийом; нічого не заборонено, важливі порції.'},
  'diet.plan.highProtein.name': {'en': 'Higher protein', 'ru': 'С упором на белок', 'uk': 'З акцентом на білок'},
  'diet.plan.highProtein.summary': {'en': 'More protein to keep muscle while losing fat or to build it. Keeps you full longer.', 'ru': 'Больше белка, чтобы сохранить мышцы при похудении или набрать их. Дольше сытость.', 'uk': 'Більше білка, щоб зберегти м’язи при схудненні або набрати їх. Довше ситість.'},
  'diet.plan.highProtein.tips': {'en': 'Protein at every meal: eggs, chicken, fish, cottage cheese, legumes.', 'ru': 'Белок в каждый приём: яйца, курица, рыба, творог, бобовые.', 'uk': 'Білок у кожен прийом: яйця, курка, риба, сир, бобові.'},
  'diet.plan.lowCarb.name': {'en': 'Moderate low-carb', 'ru': 'Умеренно низкоуглеводная', 'uk': 'Помірно низьковуглеводна'},
  'diet.plan.lowCarb.summary': {'en': 'Fewer refined carbs and sugar, more protein and vegetables. Can speed early fat loss.', 'ru': 'Меньше быстрых углеводов и сахара, больше белка и овощей. Может ускорить похудение вначале.', 'uk': 'Менше швидких вуглеводів і цукру, більше білка й овочів. Може прискорити схуднення спочатку.'},
  'diet.plan.lowCarb.tips': {'en': 'Cut sugary drinks and white bread first; keep vegetables and healthy fats.', 'ru': 'Сначала уберите сладкие напитки и белый хлеб; оставьте овощи и полезные жиры.', 'uk': 'Спершу приберіть солодкі напої та білий хліб; залиште овочі та корисні жири.'},
  'diet.plan.fasting.name': {'en': 'Intermittent fasting 16:8', 'ru': 'Интервальное голодание 16:8', 'uk': 'Інтервальне голодування 16:8'},
  'diet.plan.fasting.summary': {'en': 'Eat within an 8-hour window, fast for 16. Simplifies calorie control for some people.', 'ru': 'Есть в течение 8 часов, 16 — перерыв. Кому-то упрощает контроль калорий.', 'uk': 'Їсти протягом 8 годин, 16 — перерва. Комусь спрощує контроль калорій.'},
  'diet.plan.fasting.tips': {'en': 'Try 12:00-20:00; water, tea and black coffee are fine during the fast.', 'ru': 'Попробуйте 12:00–20:00; вода, чай и чёрный кофе можно в голодном окне.', 'uk': 'Спробуйте 12:00–20:00; вода, чай і чорна кава можна в голодному вікні.'},
  'diet.tapForDetails': {'en': 'Tap for the breakdown, pros & cons', 'ru': 'Нажмите — разбор, плюсы и минусы', 'uk': 'Натисніть — розбір, плюси й мінуси'},
  'diet.howTitle': {'en': 'How it works', 'ru': 'Как работает', 'uk': 'Як працює'},
  'diet.pros': {'en': 'Pros', 'ru': 'Плюсы', 'uk': 'Плюси'},
  'diet.cons': {'en': 'Cons', 'ru': 'Минусы', 'uk': 'Мінуси'},
  'diet.howToStart': {'en': 'How to start', 'ru': 'Как начать', 'uk': 'Як почати'},
  'diet.notAdvice': {'en': 'Educational information, not medical advice. If you have any health conditions, consult a doctor first.', 'ru': 'Это образовательная информация, не медицинская рекомендация. При заболеваниях сначала проконсультируйтесь с врачом.', 'uk': 'Це освітня інформація, не медична рекомендація. За наявності захворювань спершу проконсультуйтеся з лікарем.'},
  'meddiet.title': {'en': 'Medical (therapeutic) diets', 'ru': 'Врачебные диеты', 'uk': 'Лікарські дієти'},
  'meddiet.sub': {'en': 'Only on a doctor’s prescription. Mark the one prescribed to you.', 'ru': 'Только по назначению врача. Отметьте ту, что вам назначили.', 'uk': 'Лише за призначенням лікаря. Позначте ту, що вам призначили.'},
  'meddiet.prescribed': {'en': 'Prescribed', 'ru': 'Назначено', 'uk': 'Призначено'},
  'meddiet.eat': {'en': 'What to eat', 'ru': 'Что можно', 'uk': 'Що можна'},
  'meddiet.avoid': {'en': 'What to avoid', 'ru': 'Чего избегать', 'uk': 'Чого уникати'},
  'meddiet.cook': {'en': 'How to cook', 'ru': 'Как готовить', 'uk': 'Як готувати'},
  'meddiet.myDoctor': {'en': 'My doctor prescribed this', 'ru': 'Мне назначил это врач', 'uk': 'Мені призначив це лікар'},
  'meddiet.disclaimer': {'en': 'Therapeutic diets are used only as prescribed by a doctor. The app does not diagnose or prescribe.', 'ru': 'Лечебные диеты применяются только по назначению врача. Приложение не ставит диагноз и не назначает.', 'uk': 'Лікувальні дієти застосовуються лише за призначенням лікаря. Застосунок не діагностує й не призначає.'},
  'meddiet.table1.name': {'en': 'Table 1', 'ru': 'Стол №1', 'uk': 'Стіл №1'},
  'meddiet.table1.condition': {'en': 'Gastritis and ulcer (recovery phase)', 'ru': 'Гастрит и язва в стадии затихания', 'uk': 'Гастрит і виразка у стадії затихання'},
  'meddiet.table1.eat': {'en': 'Puréed porridge, mucous soups, lean boiled meat and fish, steamed omelettes, kissel, dried bread, non-sour dairy.', 'ru': 'Протёртые каши, слизистые супы, нежирное отварное мясо и рыба, паровые омлеты, кисели, подсушенный хлеб, некислые молочные продукты.', 'uk': 'Протерті каші, слизові супи, нежирне відварене м’ясо й риба, парові омлети, киселі, підсушений хліб, некислі молочні продукти.'},
  'meddiet.table1.avoid': {'en': 'Spicy, fried, smoked, sour, fresh bread, soda, coffee, coarse fibre, very hot or cold food.', 'ru': 'Острое, жареное, копчёное, кислое, свежий хлеб, газировку, кофе, грубую клетчатку, очень горячее и холодное.', 'uk': 'Гостре, смажене, копчене, кисле, свіжий хліб, газованку, каву, грубу клітковину, дуже гаряче й холодне.'},
  'meddiet.table1.cook': {'en': 'Boil, steam, bake without a crust; serve warm and puréed.', 'ru': 'Варить, готовить на пару, запекать без корочки; подавать тёплым и протёртым.', 'uk': 'Варити, готувати на парі, запікати без скоринки; подавати теплим і протертим.'},
  'meddiet.table5.name': {'en': 'Table 5', 'ru': 'Стол №5', 'uk': 'Стіл №5'},
  'meddiet.table5.condition': {'en': 'Liver and gallbladder conditions', 'ru': 'Болезни печени и желчного пузыря', 'uk': 'Хвороби печінки й жовчного міхура'},
  'meddiet.table5.eat': {'en': 'Lean meat and fish, grains, vegetable soups, cottage cheese, cooked vegetables, fruit, dried bread.', 'ru': 'Нежирное мясо и рыба, крупы, овощные супы, творог, отварные овощи, фрукты, подсушенный хлеб.', 'uk': 'Нежирне м’ясо й риба, крупи, овочеві супи, сир, відварені овочі, фрукти, підсушений хліб.'},
  'meddiet.table5.avoid': {'en': 'Fatty, fried, excess egg yolk, legumes, onion/garlic, cocoa, alcohol, pastry.', 'ru': 'Жирное, жареное, избыток желтка, бобовые, лук/чеснок, какао, алкоголь, сдобу.', 'uk': 'Жирне, смажене, надлишок жовтка, бобові, цибулю/часник, какао, алкоголь, здобу.'},
  'meddiet.table5.cook': {'en': 'Boil, stew, bake; no frying or harsh spices.', 'ru': 'Варить, тушить, запекать; без жарки и грубых специй.', 'uk': 'Варити, тушкувати, запікати; без смаження і грубих спецій.'},
  'meddiet.table7.name': {'en': 'Table 7', 'ru': 'Стол №7', 'uk': 'Стіл №7'},
  'meddiet.table7.condition': {'en': 'Kidney conditions', 'ru': 'Болезни почек', 'uk': 'Хвороби нирок'},
  'meddiet.table7.eat': {'en': 'Vegetables, fruit, grains, limited protein, salt-free bread; protein amount per doctor.', 'ru': 'Овощи, фрукты, крупы, ограниченный белок, безсолевой хлеб; количество белка по назначению врача.', 'uk': 'Овочі, фрукти, крупи, обмежений білок, безсольовий хліб; кількість білка за призначенням лікаря.'},
  'meddiet.table7.avoid': {'en': 'Salt (sharply limited), broths, smoked foods, legumes, excess protein.', 'ru': 'Соль (резко ограничить), бульоны, копчёности, бобовые, избыток белка.', 'uk': 'Сіль (різко обмежити), бульйони, копченості, бобові, надлишок білка.'},
  'meddiet.table7.cook': {'en': 'Boil and bake without salt; salt is added in measured amounts as prescribed.', 'ru': 'Варить и запекать без соли; соль добавляют дозированно по назначению.', 'uk': 'Варити й запікати без солі; сіль додають дозовано за призначенням.'},
  'meddiet.table8.name': {'en': 'Table 8', 'ru': 'Стол №8', 'uk': 'Стіл №8'},
  'meddiet.table8.condition': {'en': 'Obesity, weight loss', 'ru': 'Ожирение, снижение веса', 'uk': 'Ожиріння, зниження ваги'},
  'meddiet.table8.eat': {'en': 'Vegetables, lean protein, whole grains in moderation; plenty of fibre and water.', 'ru': 'Овощи, нежирный белок, цельные крупы в меру; много клетчатки и воды.', 'uk': 'Овочі, нежирний білок, цільні крупи в міру; багато клітковини й води.'},
  'meddiet.table8.avoid': {'en': 'Sugar and sweets, pastry, fatty food, fast food, sugary drinks, alcohol.', 'ru': 'Сахар и сладкое, выпечку, жирное, фастфуд, сладкие напитки, алкоголь.', 'uk': 'Цукор і солодке, випічку, жирне, фастфуд, солодкі напої, алкоголь.'},
  'meddiet.table8.cook': {'en': 'Boil, steam, bake without oil; keep portions moderate.', 'ru': 'Варить, готовить на пару, запекать без масла; порции умеренные.', 'uk': 'Варити, готувати на парі, запікати без олії; порції помірні.'},
  'meddiet.table9.name': {'en': 'Table 9', 'ru': 'Стол №9', 'uk': 'Стіл №9'},
  'meddiet.table9.condition': {'en': 'Diabetes', 'ru': 'Сахарный диабет', 'uk': 'Цукровий діабет'},
  'meddiet.table9.eat': {'en': 'Vegetables, protein, whole grains, unsweetened fruit; spread evenly across meals; count carbs.', 'ru': 'Овощи, белок, цельные крупы, несладкие фрукты; равномерно по приёмам; считать углеводы.', 'uk': 'Овочі, білок, цільні крупи, несолодкі фрукти; рівномірно по прийомах; рахувати вуглеводи.'},
  'meddiet.table9.avoid': {'en': 'Sugar, sweets, white bread, sugary drinks, excess fast carbs.', 'ru': 'Сахар, сладости, белый хлеб, сладкие напитки, избыток быстрых углеводов.', 'uk': 'Цукор, солодощі, білий хліб, солодкі напої, надлишок швидких вуглеводів.'},
  'meddiet.table9.cook': {'en': 'Boil, stew, bake; no sugar, mind the glycaemic index.', 'ru': 'Варить, тушить, запекать; без сахара, следить за гликемическим индексом.', 'uk': 'Варити, тушкувати, запікати; без цукру, стежити за глікемічним індексом.'},
  'meddiet.table10.name': {'en': 'Table 10', 'ru': 'Стол №10', 'uk': 'Стіл №10'},
  'meddiet.table10.condition': {'en': 'Heart conditions and high blood pressure', 'ru': 'Болезни сердца и повышенное давление', 'uk': 'Хвороби серця й підвищений тиск'},
  'meddiet.table10.eat': {'en': 'Vegetables, fruit, fish, lean meat, grains, low-fat dairy; potassium and magnesium.', 'ru': 'Овощи, фрукты, рыба, нежирное мясо, крупы, нежирные молочные; калий и магний.', 'uk': 'Овочі, фрукти, риба, нежирне м’ясо, крупи, нежирні молочні; калій і магній.'},
  'meddiet.table10.avoid': {'en': 'Salt, fatty food, smoked foods, strong coffee, alcohol, sweets.', 'ru': 'Соль, жирное, копчёности, крепкий кофе, алкоголь, сладкое.', 'uk': 'Сіль, жирне, копченості, міцну каву, алкоголь, солодке.'},
  'meddiet.table10.cook': {'en': 'Boil and bake with minimal salt; no frying.', 'ru': 'Варить и запекать с минимумом соли; жарку исключить.', 'uk': 'Варити й запікати з мінімумом солі; смаження виключити.'},
  'diet.history': {'en': 'History', 'ru': 'История', 'uk': 'Історія'},
  'diet.expert': {'en': 'What doctors say', 'ru': 'Мнение врачей', 'uk': 'Думка лікарів'},
  'diet.contra': {'en': 'Contraindications', 'ru': 'Противопоказания', 'uk': 'Протипоказання'},
  'diet.plan.mediterranean.history': {'en': 'Described in the 1960s from the traditional eating of Crete and southern Italy, and popularised by the American physiologist Ancel Keys through his Seven Countries Study.', 'ru': 'Описана в 1960-х на основе традиционного питания жителей Крита и Южной Италии; популяризирована американским физиологом Анселом Кизом в «Исследовании семи стран».', 'uk': 'Описана в 1960-х на основі традиційного харчування жителів Криту та Південної Італії; популяризована американським фізіологом Анселом Кізом у «Дослідженні семи країн».'},
  'diet.plan.mediterranean.expert': {'en': 'Regularly ranked by dietitians among the healthiest diets and recommended by cardiologists (incl. the American Heart Association) for heart health.', 'ru': 'Диетологи регулярно называют её одной из самых здоровых; кардиологи (в т.ч. Американская кардиологическая ассоциация) рекомендуют её для сердца.', 'uk': 'Дієтологи регулярно називають її однією з найздоровіших; кардіологи (зокрема Американська кардіологічна асоціація) рекомендують її для серця.'},
  'diet.plan.mediterranean.contra': {'en': 'Generally very safe. Take care with fish or nut allergies; with IBS, introduce legumes and fibre gradually.', 'ru': 'В целом очень безопасна. Осторожно при аллергии на рыбу или орехи; при СРК вводите бобовые и клетчатку постепенно.', 'uk': 'Загалом дуже безпечна. Обережно за алергії на рибу чи горіхи; за СПК вводьте бобові й клітковину поступово.'},
  'diet.plan.dash.history': {'en': 'Developed in the 1990s for the US National Heart, Lung, and Blood Institute (NHLBI) specifically to lower high blood pressure.', 'ru': 'Разработана в 1990-х по заказу Национального института сердца, лёгких и крови США (NHLBI) специально для снижения повышенного давления.', 'uk': 'Розроблена в 1990-х на замовлення Національного інституту серця, легень і крові США (NHLBI) спеціально для зниження підвищеного тиску.'},
  'diet.plan.dash.expert': {'en': 'Consistently ranked near the top of expert diet rankings (US News) and recommended by cardiologists and nephrologists.', 'ru': 'Годами занимает верхние строчки экспертных рейтингов диет (US News); рекомендована кардиологами и нефрологами.', 'uk': 'Роками посідає верхні щаблі експертних рейтингів дієт (US News); рекомендована кардіологами й нефрологами.'},
  'diet.plan.dash.contra': {'en': 'With kidney disease, potassium and protein must be watched with a doctor; if you take blood-pressure medication, do not cut salt sharply without advice.', 'ru': 'При болезнях почек калий и белок контролируйте с врачом; при приёме лекарств от давления не снижайте соль резко без консультации.', 'uk': 'За хвороб нирок калій і білок контролюйте з лікарем; за прийому ліків від тиску не знижуйте сіль різко без консультації.'},
  'diet.plan.balanced.history': {'en': 'Based on official dietary guidelines — the "healthy plate" principle from the Harvard School of Public Health and the WHO.', 'ru': 'Основана на официальных рекомендациях по питанию — принципе «здоровой тарелки» Гарвардской школы здоровья и ВОЗ.', 'uk': 'Заснована на офіційних рекомендаціях щодо харчування — принципі «здорової тарілки» Гарвардської школи здоров’я та ВООЗ.'},
  'diet.plan.balanced.expert': {'en': 'Dietitians consider it the safest baseline approach for most people, with no food groups excluded.', 'ru': 'Диетологи считают его самым безопасным базовым подходом для большинства людей, без исключения групп продуктов.', 'uk': 'Дієтологи вважають його найбезпечнішим базовим підходом для більшості людей, без виключення груп продуктів.'},
  'diet.plan.balanced.contra': {'en': 'Practically none. With specific conditions, adjust portions and food choices with a doctor.', 'ru': 'Практически нет. При особых состояниях адаптируйте порции и выбор продуктов с врачом.', 'uk': 'Практично немає. За особливих станів адаптуйте порції та вибір продуктів з лікарем.'},
  'diet.plan.highProtein.history': {'en': 'Came from sports nutrition and bodybuilding, and gained ground through research on preserving muscle during weight loss.', 'ru': 'Пришла из спортивной диетологии и бодибилдинга; укрепилась благодаря исследованиям сохранения мышц при похудении.', 'uk': 'Прийшла зі спортивної дієтології та бодібілдингу; зміцнилася завдяки дослідженням збереження м’язів при схудненні.'},
  'diet.plan.highProtein.expert': {'en': 'Sports dietitians recommend it for keeping and building muscle; studies back its effect on fullness and satiety.', 'ru': 'Спортивные диетологи рекомендуют её для сохранения и роста мышц; исследования подтверждают влияние на сытость.', 'uk': 'Спортивні дієтологи рекомендують її для збереження та росту м’язів; дослідження підтверджують вплив на ситість.'},
  'diet.plan.highProtein.contra': {'en': 'With kidney disease or gout, use only under a doctor. Keep fibre and water high; not for those needing protein restriction.', 'ru': 'При болезнях почек или подагре — только под наблюдением врача. Держите клетчатку и воду высокими; не подходит при необходимости ограничить белок.', 'uk': 'За хвороб нирок або подагри — лише під наглядом лікаря. Тримайте клітковину й воду високими; не підходить за потреби обмежити білок.'},
  'diet.plan.lowCarb.history': {'en': 'Low-carb ideas date back to William Banting (1863); the modern wave came with Atkins in the 1970s and later keto.', 'ru': 'Идеи низкоуглеводного питания восходят к Уильяму Бантингу (1863); современная волна — Аткинс (1970-е) и позже кето.', 'uk': 'Ідеї низьковуглеводного харчування сягають Вільяма Бантінга (1863); сучасна хвиля — Аткінс (1970-ті) і згодом кето.'},
  'diet.plan.lowCarb.expert': {'en': 'Opinions are split: some doctors note fast results and better blood-sugar control, others stress long-term balance.', 'ru': 'Мнения разделяются: часть врачей отмечают быстрый результат и контроль сахара, другие подчёркивают важность долгосрочного баланса.', 'uk': 'Думки поділяються: частина лікарів відзначають швидкий результат і контроль цукру, інші наголошують на важливості довгострокового балансу.'},
  'diet.plan.lowCarb.contra': {'en': 'Only under supervision with type 1 diabetes, kidney disease or pregnancy. With gastritis or ulcer, excess fat and acidity can aggravate symptoms.', 'ru': 'При диабете 1 типа, болезнях почек, беременности — только под наблюдением. При гастрите или язве избыток жиров и кислого может обострять симптомы.', 'uk': 'За діабету 1 типу, хвороб нирок, вагітності — лише під наглядом. За гастриту чи виразки надлишок жирів і кислого може загострювати симптоми.'},
  'diet.plan.fasting.history': {'en': 'Fasting practices are ancient; scientific interest in 16:8 grew in the 2010s through the work of Satchin Panda and Mark Mattson.', 'ru': 'Практики голодания известны тысячелетиями; научный интерес к 16:8 вырос в 2010-х благодаря работам Сатчина Панды и Марка Мэттсона.', 'uk': 'Практики голодування відомі тисячоліттями; науковий інтерес до 16:8 зріс у 2010-х завдяки працям Сатчіна Панди та Марка Меттсона.'},
  'diet.plan.fasting.expert': {'en': 'Some doctors note metabolic benefits, but there is no consensus that it beats a plain calorie deficit.', 'ru': 'Часть врачей отмечают пользу для метаболизма, но консенсуса о превосходстве над обычным дефицитом калорий нет.', 'uk': 'Частина лікарів відзначають користь для метаболізму, але консенсусу щодо переваги над звичайним дефіцитом калорій немає.'},
  'diet.plan.fasting.contra': {'en': 'Not advised without a doctor for diabetes, eating disorders, pregnancy/breastfeeding or teenagers. With gastritis or ulcer, long gaps can worsen pain.', 'ru': 'Не рекомендуется без врача при диабете, расстройствах пищевого поведения, беременности/ГВ и у подростков. При гастрите или язве длинные перерывы могут усиливать боль.', 'uk': 'Не рекомендується без лікаря за діабету, розладів харчової поведінки, вагітності/ГВ і в підлітків. За гастриту чи виразки довгі перерви можуть посилювати біль.'},
  'diet.otherDish': {'en': 'Another dish', 'ru': 'Другое блюдо', 'uk': 'Інша страва'},
  'recipe.title': {'en': 'Recipe', 'ru': 'Рецепт', 'uk': 'Рецепт'},
  'recipe.chooseMethod': {'en': 'Cooking method', 'ru': 'Способ приготовления', 'uk': 'Спосіб приготування'},
  'recipe.flavor': {'en': 'What each ingredient adds', 'ru': 'Что даёт каждый продукт', 'uk': 'Що дає кожен продукт'},
  'recipe.chefNote': {'en': 'Based on restaurant techniques — precise time and temperature give a consistent result.', 'ru': 'По мотивам ресторанных техник — точные время и температура дают стабильный результат.', 'uk': 'За мотивами ресторанних технік — точні час і температура дають стабільний результат.'},
  'recipe.method.pan': {'en': 'Pan', 'ru': 'Сковорода', 'uk': 'Сковорода'},
  'recipe.method.oven': {'en': 'Oven', 'ru': 'Духовка', 'uk': 'Духовка'},
  'recipe.method.pot': {'en': 'Pot', 'ru': 'Кастрюля', 'uk': 'Каструля'},
  'recipe.method.multicooker': {'en': 'Multicooker', 'ru': 'Мультиварка', 'uk': 'Мультиварка'},
  'recipe.method.airfryer': {'en': 'Air fryer', 'ru': 'Аэрогриль', 'uk': 'Аерогриль'},
  'recipe.method.grill': {'en': 'Grill / BBQ', 'ru': 'Гриль / мангал', 'uk': 'Гриль / мангал'},
  'recipe.method.microwave': {'en': 'Microwave', 'ru': 'Микроволновка', 'uk': 'Мікрохвильовка'},
  'recipe.method.assembly': {'en': 'No cooking', 'ru': 'Без готовки', 'uk': 'Без готування'},
  'recipe.casserole.oven': {'en': 'Heat the oven to 180 °C.\nBlend cottage cheese, eggs, honey and flour until smooth (5 min).\nPour into a greased dish, level the top, brush with egg or sour cream.\nBake 30-35 min until golden; rest 10 min before slicing.', 'ru': 'Разогрейте духовку до 180 °C.\nРазотрите творог с яйцами, мёдом и мукой до однородности (5 мин).\nВыложите в смазанную форму, разровняйте, смажьте верх яйцом или сметаной.\nВыпекайте 30–35 мин до золотистой корочки; дайте постоять 10 мин перед нарезкой.', 'uk': 'Розігрійте духовку до 180 °C.\nРозітріть сир з яйцями, медом і борошном до однорідності (5 хв).\nВикладіть у змащену форму, розрівняйте, змастіть верх яйцем або сметаною.\nВипікайте 30–35 хв до золотистої скоринки; дайте постояти 10 хв перед нарізанням.'},
  'recipe.casserole.multicooker': {'en': 'Blend cottage cheese, eggs, honey and flour smooth.\nGrease the bowl and add the mix.\n"Bake" mode for 50 min.\nCool 10 min, lift out on the steamer tray.', 'ru': 'Смешайте творог, яйца, мёд и муку до гладкой массы.\nСмажьте чашу маслом, выложите массу.\nРежим «Выпечка» 50 мин.\nОстудите 10 мин, достаньте на подставке для пара.', 'uk': 'Змішайте сир, яйця, мед і борошно до гладкої маси.\nЗмастіть чашу олією, викладіть масу.\nРежим «Випічка» 50 хв.\nОстудіть 10 хв, дістаньте на підставці для пари.'},
  'recipe.casserole.flavor': {'en': 'Cottage cheese — protein and a tender crumb.\nEggs — bind the mix and add fluffiness.\nHoney — natural sweetness and a golden crust.\nFlour — holds the shape.', 'ru': 'Творог — белок и нежная текстура.\nЯйца — связывают массу, дают пышность.\nМёд — сладость и румяная корочка.\nМука — держит форму.', 'uk': 'Сир — білок і ніжна текстура.\nЯйця — зв’язують масу, дають пишність.\nМед — солодкість і рум’яна скоринка.\nБорошно — тримає форму.'},
  'recipe.oatmeal.pot': {'en': 'Bring milk to a gentle simmer (3-4 min), stirring.\nAdd oats, lower the heat, cook 5-7 min, stirring.\nOff the heat, cover, rest 2 min.\nTop with sliced banana and walnuts.', 'ru': 'Доведите молоко до лёгкого кипения (3–4 мин), помешивая.\nВсыпьте овсянку, убавьте огонь, варите 5–7 мин, помешивая.\nСнимите с огня, накройте, дайте настояться 2 мин.\nДобавьте нарезанный банан и орехи.', 'uk': 'Доведіть молоко до легкого кипіння (3–4 хв), помішуючи.\nВсипте вівсянку, зменшіть вогонь, варіть 5–7 хв, помішуючи.\nЗніміть з вогню, накрийте, дайте настоятися 2 хв.\nДодайте нарізаний банан і горіхи.'},
  'recipe.oatmeal.microwave': {'en': 'Mix oats and milk in a deep bowl.\nMicrowave on full 2 min, stir.\n1-2 min more to your thickness (watch it does not boil over).\nAdd banana and walnuts, rest 1 min.', 'ru': 'Смешайте овсянку и молоко в глубокой миске.\nСВЧ на полной мощности 2 мин, перемешайте.\nЕщё 1–2 мин до нужной густоты (следите, чтобы не убежало).\nДобавьте банан и орехи, дайте постоять 1 мин.', 'uk': 'Змішайте вівсянку й молоко в глибокій мисці.\nНВЧ на повній потужності 2 хв, перемішайте.\nЩе 1–2 хв до потрібної густоти (стежте, щоб не втекло).\nДодайте банан і горіхи, дайте постояти 1 хв.'},
  'recipe.oatmeal.flavor': {'en': 'Oats — slow carbs and staying power.\nMilk — creaminess and protein.\nBanana — natural sweetness and potassium.\nWalnuts — crunch and healthy fats.', 'ru': 'Овсянка — медленные углеводы и сытость.\nМолоко — кремовость и белок.\nБанан — натуральная сладость и калий.\nОрехи — хруст и полезные жиры.', 'uk': 'Вівсянка — повільні вуглеводи і ситість.\nМолоко — кремовість і білок.\nБанан — натуральна солодкість і калій.\nГоріхи — хрускіт і корисні жири.'},
  'recipe.syrnyky.pan': {'en': 'Mix cottage cheese, egg, honey and half the flour into a dough.\nShape small patties, dust with flour.\nFry on medium 3-4 min per side until golden.\nCover 1 min so they warm through.', 'ru': 'Смешайте творог, яйцо, мёд и половину муки в тесто.\nСформуйте небольшие сырники, обваляйте в муке.\nЖарьте на среднем огне 3–4 мин с каждой стороны до румяности.\nНакройте на 1 мин, чтобы прогрелись внутри.', 'uk': 'Змішайте сир, яйце, мед і половину борошна в тісто.\nСформуйте невеликі сирники, обваляйте в борошні.\nСмажте на середньому вогні 3–4 хв з кожного боку до рум’яності.\nНакрийте на 1 хв, щоб прогрілися всередині.'},
  'recipe.syrnyky.airfryer': {'en': 'Shape the patties, spritz lightly with oil.\nAir fry at 180 °C for 12-14 min, flip halfway.\nRest 2 min.', 'ru': 'Сформуйте сырники, слегка сбрызните маслом.\nАэрогриль 180 °C, 12–14 мин, переверните на середине.\nДайте постоять 2 мин.', 'uk': 'Сформуйте сирники, злегка збризніть олією.\nАерогриль 180 °C, 12–14 хв, переверніть на середині.\nДайте постояти 2 хв.'},
  'recipe.syrnyky.flavor': {'en': 'Cottage cheese — protein and tenderness.\nEgg — binder.\nHoney — sweetness without sugar.\nFlour — shape and browning.', 'ru': 'Творог — белок и нежность.\nЯйцо — связка.\nМёд — сладость без сахара.\nМука — форма и румяность.', 'uk': 'Сир — білок і ніжність.\nЯйце — зв’язка.\nМед — солодкість без цукру.\nБорошно — форма і рум’яність.'},
  'recipe.omelette.pan': {'en': 'Whisk eggs with milk and a pinch of salt until frothy.\nOn medium, cook the sliced tomatoes 1-2 min.\nPour in the eggs, cook covered 3-4 min.\nSprinkle cheese, fold in half, remove after 1 min.', 'ru': 'Взбейте яйца с молоком и щепоткой соли до пены.\nНа среднем огне обжарьте нарезанные помидоры 1–2 мин.\nВлейте яйца, готовьте под крышкой 3–4 мин.\nПосыпьте сыром, сложите пополам, снимите через 1 мин.', 'uk': 'Збийте яйця з молоком і дрібкою солі до піни.\nНа середньому вогні обсмажте нарізані помідори 1–2 хв.\nВлийте яйця, готуйте під кришкою 3–4 хв.\nПосипте сиром, складіть навпіл, зніміть за 1 хв.'},
  'recipe.omelette.oven': {'en': 'Heat the oven to 180 °C.\nWhisk eggs with milk, stir in tomatoes and cheese.\nPour into a dish, bake 15-18 min until just set.', 'ru': 'Разогрейте духовку до 180 °C.\nВзбейте яйца с молоком, добавьте помидоры и сыр.\nВылейте в форму, запекайте 15–18 мин до схватывания.', 'uk': 'Розігрійте духовку до 180 °C.\nЗбийте яйця з молоком, додайте помідори й сир.\nВилийте у форму, запікайте 15–18 хв до схоплення.'},
  'recipe.omelette.flavor': {'en': 'Eggs — protein and structure.\nMilk — tenderness.\nTomatoes — juiciness and a touch of acidity.\nCheese — creamy taste and a crust.', 'ru': 'Яйца — белок и структура.\nМолоко — нежность.\nПомидоры — сочность и кислинка.\nСыр — сливочный вкус и корочка.', 'uk': 'Яйця — білок і структура.\nМолоко — ніжність.\nПомідори — соковитість і кислинка.\nСир — вершковий смак і скоринка.'},
  'recipe.borscht.pot': {'en': 'Simmer the beef 40-60 min, skimming; remove and slice.\nAdd potatoes to the broth (10 min), then cabbage.\nSeparately sauté beetroot, carrot and onion 10 min, add to the pot.\nReturn the meat, cook 5 min, rest 15 min.', 'ru': 'Отварите говядину 40–60 мин, снимая пену; выньте и нарежьте.\nВ бульон добавьте картофель (10 мин), затем капусту.\nОтдельно потушите свёклу, морковь и лук 10 мин, добавьте в кастрюлю.\nВерните мясо, варите 5 мин, дайте настояться 15 мин.', 'uk': 'Відваріть яловичину 40–60 хв, знімаючи піну; вийміть і наріжте.\nУ бульйон додайте картоплю (10 хв), потім капусту.\nОкремо потушкуйте буряк, моркву й цибулю 10 хв, додайте в каструлю.\nПоверніть м’ясо, варіть 5 хв, дайте настоятися 15 хв.'},
  'recipe.borscht.multicooker': {'en': '"Fry" mode: sauté onion, carrot and beetroot 10 min.\nAdd meat, potatoes and water.\n"Soup/Stew" mode for 1 hour.\nRest 15 min before serving.', 'ru': 'Режим «Жарка»: обжарьте лук, морковь и свёклу 10 мин.\nДобавьте мясо, картофель и воду.\nРежим «Суп/Тушение» 1 час.\nДайте настояться 15 мин перед подачей.', 'uk': 'Режим «Смаження»: обсмажте цибулю, моркву й буряк 10 хв.\nДодайте м’ясо, картоплю й воду.\nРежим «Суп/Тушкування» 1 година.\nДайте настоятися 15 хв перед подачею.'},
  'recipe.borscht.flavor': {'en': 'Beef — a rich broth and protein.\nBeetroot — colour and sweetness.\nPotatoes — heartiness.\nCarrot and onion — the aromatic base.', 'ru': 'Говядина — насыщенный бульон и белок.\nСвёкла — цвет и сладость.\nКартофель — сытность.\nМорковь и лук — ароматная база.', 'uk': 'Яловичина — насичений бульйон і білок.\nБуряк — колір і солодкість.\nКартопля — ситність.\nМорква й цибуля — ароматна база.'},
  'recipe.buckwheat_chicken.pot': {'en': 'Rinse buckwheat, add water 1:2, cook 15 min covered.\nSauté onion and carrot 5 min, add diced chicken.\nCook the chicken 8-10 min until golden.\nCombine with the buckwheat, warm 2 min.', 'ru': 'Промойте гречку, залейте водой 1:2, варите 15 мин под крышкой.\nОбжарьте лук и морковь 5 мин, добавьте курицу кубиками.\nГотовьте курицу 8–10 мин до золотистости.\nСоедините с гречкой, прогрейте 2 мин.', 'uk': 'Промийте гречку, залийте водою 1:2, варіть 15 хв під кришкою.\nОбсмажте цибулю й моркву 5 хв, додайте курку кубиками.\nГотуйте курку 8–10 хв до золотистості.\nЗ’єднайте з гречкою, прогрійте 2 хв.'},
  'recipe.buckwheat_chicken.oven': {'en': 'Heat the oven to 190 °C.\nCombine buckwheat, chicken, onion, carrot and water in a dish.\nCover with foil, bake 30 min, uncover for the last 10 min.', 'ru': 'Разогрейте духовку до 190 °C.\nСмешайте гречку, курицу, лук, морковь и воду в форме.\nНакройте фольгой, запекайте 30 мин, снимите фольгу на последние 10 мин.', 'uk': 'Розігрійте духовку до 190 °C.\nЗмішайте гречку, курку, цибулю, моркву й воду у формі.\nНакрийте фольгою, запікайте 30 хв, зніміть фольгу на останні 10 хв.'},
  'recipe.buckwheat_chicken.flavor': {'en': 'Chicken — lean protein.\nBuckwheat — slow carbs and iron.\nCarrot — sweetness.\nOnion — aroma.', 'ru': 'Курица — постный белок.\nГречка — медленные углеводы и железо.\nМорковь — сладость.\nЛук — аромат.', 'uk': 'Курка — пісний білок.\nГречка — повільні вуглеводи і залізо.\nМорква — солодкість.\nЦибуля — аромат.'},
  'recipe.rice_fish.pan': {'en': 'Boil the rice 12-15 min, drain.\nPan-fry the fish on medium 3-4 min per side.\nSlice the vegetables, dress with oil and salt.\nServe the fish with rice and salad.', 'ru': 'Отварите рис 12–15 мин, откиньте.\nОбжарьте рыбу на среднем огне 3–4 мин с каждой стороны.\nНарежьте овощи, заправьте маслом и солью.\nПодавайте рыбу с рисом и салатом.', 'uk': 'Відваріть рис 12–15 хв, відкиньте.\nОбсмажте рибу на середньому вогні 3–4 хв з кожного боку.\nНаріжте овочі, заправте олією й сіллю.\nПодавайте рибу з рисом і салатом.'},
  'recipe.rice_fish.oven': {'en': 'Heat the oven to 200 °C.\nSalt the fish, drizzle with lemon and oil.\nBake 15-18 min; cook the rice alongside.', 'ru': 'Разогрейте духовку до 200 °C.\nРыбу посолите, сбрызните лимоном и маслом.\nЗапекайте 15–18 мин; рис отварите параллельно.', 'uk': 'Розігрійте духовку до 200 °C.\nРибу посоліть, збризніть лимоном і олією.\nЗапікайте 15–18 хв; рис відваріть паралельно.'},
  'recipe.rice_fish.flavor': {'en': 'Fish — protein and omega-3.\nRice — the energy side.\nCucumber and tomato — freshness and vitamins.', 'ru': 'Рыба — белок и омега-3.\nРис — гарнир и энергия.\nОгурцы и помидоры — свежесть и витамины.', 'uk': 'Риба — білок і омега-3.\nРис — гарнір і енергія.\nОгірки й помідори — свіжість і вітаміни.'},
  'recipe.baked_chicken.oven': {'en': 'Heat the oven to 200 °C.\nRub the chicken with salt, pepper and oil, rest 10 min.\nBake 22-25 min to 74 °C inside.\nRest 5 min; serve with fresh salad and cheese.', 'ru': 'Разогрейте духовку до 200 °C.\nКурицу натрите солью, перцем и маслом, дайте 10 мин.\nЗапекайте 22–25 мин до 74 °C внутри.\nДайте отдохнуть 5 мин; подайте со свежим салатом и сыром.', 'uk': 'Розігрійте духовку до 200 °C.\nКурку натріть сіллю, перцем і олією, дайте 10 хв.\nЗапікайте 22–25 хв до 74 °C всередині.\nДайте відпочити 5 хв; подайте зі свіжим салатом і сиром.'},
  'recipe.baked_chicken.airfryer': {'en': 'Rub the chicken with spices and a little oil.\nAir fry at 190 °C for 18 min, flip halfway.\nJuices should run clear; rest 5 min.', 'ru': 'Натрите курицу специями и каплей масла.\nАэрогриль 190 °C, 18 мин, переверните на середине.\nСок должен быть прозрачным; отдых 5 мин.', 'uk': 'Натріть курку спеціями й краплею олії.\nАерогриль 190 °C, 18 хв, переверніть на середині.\nСік має бути прозорим; відпочинок 5 хв.'},
  'recipe.baked_chicken.grill': {'en': 'Marinate the chicken 20 min (oil, salt, spices).\nCook over medium heat 6-7 min per side, not over open flame.\nRest 5 min so the juices settle.', 'ru': 'Замаринуйте курицу 20 мин (масло, соль, специи).\nГотовьте на среднем жаре 6–7 мин с каждой стороны, не над открытым пламенем.\nДайте отдохнуть 5 мин, чтобы сок распределился.', 'uk': 'Замаринуйте курку 20 хв (олія, сіль, спеції).\nГотуйте на середньому жарі 6–7 хв з кожного боку, не над відкритим полум’ям.\nДайте відпочити 5 хв, щоб сік розподілився.'},
  'recipe.baked_chicken.flavor': {'en': 'Chicken — the main protein.\nTomatoes — juiciness and lycopene.\nCucumbers — freshness.\nCheese — a creamy accent.', 'ru': 'Курица — основной белок.\nПомидоры — сочность и ликопин.\nОгурцы — свежесть.\nСыр — сливочный акцент.', 'uk': 'Курка — основний білок.\nПомідори — соковитість і лікопін.\nОгірки — свіжість.\nСир — вершковий акцент.'},
  'recipe.stewed_fish.pot': {'en': 'Sauté onion and carrot 5 min.\nAdd diced potatoes and a little water, stew 10 min.\nLay the fish on top, stew covered 12-15 min.\nSalt, rest 5 min.', 'ru': 'Обжарьте лук и морковь 5 мин.\nДобавьте картофель кубиками и немного воды, тушите 10 мин.\nУложите рыбу сверху, тушите под крышкой 12–15 мин.\nПосолите, дайте настояться 5 мин.', 'uk': 'Обсмажте цибулю й моркву 5 хв.\nДодайте картоплю кубиками й трохи води, тушкуйте 10 хв.\nПокладіть рибу зверху, тушкуйте під кришкою 12–15 хв.\nПосоліть, дайте настоятися 5 хв.'},
  'recipe.stewed_fish.multicooker': {'en': '"Fry" mode: onion and carrot 7 min.\nAdd potatoes, fish and water.\n"Stew" mode for 40 min.', 'ru': 'Режим «Жарка»: лук и морковь 7 мин.\nДобавьте картофель, рыбу и воду.\nРежим «Тушение» 40 мин.', 'uk': 'Режим «Смаження»: цибуля й морква 7 хв.\nДодайте картоплю, рибу й воду.\nРежим «Тушкування» 40 хв.'},
  'recipe.stewed_fish.flavor': {'en': 'Fish — tender protein.\nPotatoes — heartiness.\nCarrot — sweetness.\nOnion — aroma of the sauce.', 'ru': 'Рыба — нежный белок.\nКартофель — сытность.\nМорковь — сладость.\nЛук — аромат соуса.', 'uk': 'Риба — ніжний білок.\nКартопля — ситність.\nМорква — солодкість.\nЦибуля — аромат соусу.'},
  'recipe.cottage_bowl.assembly': {'en': 'Put the cottage cheese in a bowl.\nDice the cucumber and tomato, add to the cheese.\nScatter chopped nuts, salt or drizzle with oil.', 'ru': 'Выложите творог в миску.\nНарежьте огурцы и помидоры, добавьте к творогу.\nПосыпьте рублеными орехами, посолите или сбрызните маслом.', 'uk': 'Викладіть сир у миску.\nНаріжте огірки й помідори, додайте до сиру.\nПосипте рубленими горіхами, посоліть або збризніть олією.'},
  'recipe.cottage_bowl.flavor': {'en': 'Cottage cheese — protein.\nVegetables — freshness and fibre.\nNuts — crunch and fats.', 'ru': 'Творог — белок.\nОвощи — свежесть и клетчатка.\nОрехи — хруст и жиры.', 'uk': 'Сир — білок.\nОвочі — свіжість і клітковина.\nГоріхи — хрускіт і жири.'},
  'recipe.yogurt_nuts.assembly': {'en': 'Spoon the yogurt into a glass or bowl.\nAdd chopped nuts.\nOptional: a spoon of honey or some berries.', 'ru': 'Выложите йогурт в стакан или миску.\nДобавьте рубленые орехи.\nПо желанию — ложка мёда или ягоды.', 'uk': 'Викладіть йогурт у склянку або миску.\nДодайте рублені горіхи.\nЗа бажанням — ложка меду або ягоди.'},
  'recipe.yogurt_nuts.flavor': {'en': 'Yogurt — protein and probiotics.\nNuts — healthy fats and crunch.', 'ru': 'Йогурт — белок и пробиотики.\nОрехи — полезные жиры и хруст.', 'uk': 'Йогурт — білок і пробіотики.\nГоріхи — корисні жири і хрускіт.'},
  'recipe.apple_cheese.assembly': {'en': 'Slice the apple into wedges.\nSlice the cheese.\nServe together as a snack.', 'ru': 'Нарежьте яблоко дольками.\nНарежьте сыр ломтиками.\nПодавайте вместе как перекус.', 'uk': 'Наріжте яблуко часточками.\nНаріжте сир скибочками.\nПодавайте разом як перекус.'},
  'recipe.apple_cheese.flavor': {'en': 'Apple — fibre and freshness.\nCheese — protein and a savoury taste.', 'ru': 'Яблоко — клетчатка и свежесть.\nСыр — белок и сытный вкус.', 'uk': 'Яблуко — клітковина і свіжість.\nСир — білок і ситний смак.'},
  'recipe.banana_snack.assembly': {'en': 'Peel the banana.\nEat whole or sliced; optionally with a spoon of peanut butter.', 'ru': 'Очистите банан.\nСъешьте целиком или нарежьте; по желанию — с ложкой арахисовой пасты.', 'uk': 'Очистіть банан.\nЗ’їжте цілим або наріжте; за бажанням — з ложкою арахісової пасти.'},
  'recipe.banana_snack.flavor': {'en': 'Banana — quick energy and potassium.', 'ru': 'Банан — быстрая энергия и калий.', 'uk': 'Банан — швидка енергія і калій.'},
  'recipe.protein_pancakes.pan': {'en': 'Blend oats, eggs, banana and cottage cheese into a batter.\nHeat a non-stick pan on medium, lightly oiled.\nPour small pancakes, cook 2-3 min until bubbles form, flip.\nCook 1-2 min more; serve with berries or honey.', 'ru': 'Взбейте овсянку, яйца, банан и творог в тесто.\nРазогрейте антипригарную сковороду на среднем огне, слегка смажьте.\nВылейте небольшие панкейки, жарьте 2–3 мин до пузырьков, переверните.\nГотовьте ещё 1–2 мин; подайте с ягодами или мёдом.', 'uk': 'Збийте вівсянку, яйця, банан і сир у тісто.\nРозігрійте антипригарну сковороду на середньому вогні, злегка змастіть.\nВилийте невеликі панкейки, смажте 2–3 хв до бульбашок, переверніть.\nГотуйте ще 1–2 хв; подайте з ягодами або медом.'},
  'recipe.protein_pancakes.flavor': {'en': 'Oats — slow carbs.\nEggs — protein and binding.\nBanana — natural sweetness.\nCottage cheese — extra protein and softness.', 'ru': 'Овсянка — медленные углеводы.\nЯйца — белок и связка.\nБанан — натуральная сладость.\nТворог — дополнительный белок и мягкость.', 'uk': 'Вівсянка — повільні вуглеводи.\nЯйця — білок і зв’язка.\nБанан — натуральна солодкість.\nСир — додатковий білок і м’якість.'},
  'recipe.veggie_scramble.pan': {'en': 'Dice onion and tomato.\nSoften the onion 2 min on medium, add tomato 1 min.\nPour in beaten eggs, stir gently 2-3 min to soft curds.\nOff the heat, fold in grated cheese; rest 1 min.', 'ru': 'Нарежьте лук и помидор.\nОбжарьте лук 2 мин на среднем огне, добавьте помидор на 1 мин.\nВлейте взбитые яйца, аккуратно помешивайте 2–3 мин до мягкости.\nСнимите с огня, вмешайте тёртый сыр; дайте постоять 1 мин.', 'uk': 'Наріжте цибулю й помідор.\nОбсмажте цибулю 2 хв на середньому вогні, додайте помідор на 1 хв.\nВлийте збиті яйця, обережно помішуйте 2–3 хв до м’якості.\nЗніміть з вогню, вмішайте тертий сир; дайте постояти 1 хв.'},
  'recipe.veggie_scramble.flavor': {'en': 'Eggs — protein.\nTomato — juiciness and acidity.\nCheese — creamy richness.\nOnion — aroma.', 'ru': 'Яйца — белок.\nПомидор — сочность и кислинка.\nСыр — сливочность.\nЛук — аромат.', 'uk': 'Яйця — білок.\nПомідор — соковитість і кислинка.\nСир — вершковість.\nЦибуля — аромат.'},
  'recipe.chicken_pasta.pan': {'en': 'Boil the pasta in salted water 8-10 min, drain (keep a little water).\nMeanwhile pan-fry diced chicken on medium 8 min until golden.\nAdd chopped tomato, cook 3 min into a light sauce.\nToss in the pasta with a splash of the water; finish with cheese.', 'ru': 'Отварите пасту в подсолённой воде 8–10 мин, слейте (оставьте немного воды).\nПараллельно обжарьте курицу кубиками на среднем огне 8 мин до золотистости.\nДобавьте нарезанный помидор, готовьте 3 мин до лёгкого соуса.\nВмешайте пасту с ложкой воды; завершите сыром.', 'uk': 'Відваріть пасту в підсоленій воді 8–10 хв, злийте (залиште трохи води).\nПаралельно обсмажте курку кубиками на середньому вогні 8 хв до золотистості.\nДодайте нарізаний помідор, готуйте 3 хв до легкого соусу.\nВмішайте пасту з ложкою води; завершіть сиром.'},
  'recipe.chicken_pasta.flavor': {'en': 'Chicken — lean protein.\nPasta — the energy base.\nTomato — a light sauce and acidity.\nCheese — savoury finish.', 'ru': 'Курица — постный белок.\nПаста — энергетическая основа.\nПомидор — лёгкий соус и кислинка.\nСыр — солёный акцент.', 'uk': 'Курка — пісний білок.\nПаста — енергетична основа.\nПомідор — легкий соус і кислинка.\nСир — солоний акцент.'},
  'recipe.lentil_soup.pot': {'en': 'Rinse the lentils.\nSauté onion and carrot 5 min in a pot.\nAdd lentils, diced potato and water, bring to a boil.\nSimmer 20-25 min until the lentils are soft; season.', 'ru': 'Промойте чечевицу.\nОбжарьте лук и морковь 5 мин в кастрюле.\nДобавьте чечевицу, картофель кубиками и воду, доведите до кипения.\nВарите 20–25 мин до мягкости чечевицы; посолите.', 'uk': 'Промийте сочевицю.\nОбсмажте цибулю й моркву 5 хв у каструлі.\nДодайте сочевицю, картоплю кубиками й воду, доведіть до кипіння.\nВаріть 20–25 хв до м’якості сочевиці; посоліть.'},
  'recipe.lentil_soup.multicooker': {'en': '"Fry" mode: onion and carrot 5 min.\nAdd rinsed lentils, potato and water.\n"Soup" mode for 40 min.\nRest 10 min before serving.', 'ru': 'Режим «Жарка»: лук и морковь 5 мин.\nДобавьте промытую чечевицу, картофель и воду.\nРежим «Суп» 40 мин.\nДайте настояться 10 мин перед подачей.', 'uk': 'Режим «Смаження»: цибуля й морква 5 хв.\nДодайте промиту сочевицю, картоплю й воду.\nРежим «Суп» 40 хв.\nДайте настоятися 10 хв перед подачею.'},
  'recipe.lentil_soup.flavor': {'en': 'Lentils — plant protein and fibre.\nPotato — heartiness.\nCarrot — sweetness.\nOnion — the aromatic base.', 'ru': 'Чечевица — растительный белок и клетчатка.\nКартофель — сытность.\nМорковь — сладость.\nЛук — ароматная база.', 'uk': 'Сочевиця — рослинний білок і клітковина.\nКартопля — ситність.\nМорква — солодкість.\nЦибуля — ароматна база.'},
  'recipe.beef_veg.pan': {'en': 'Sear diced beef on high 4-5 min to brown.\nAdd onion and carrot, cook 5 min.\nAdd chopped tomato and a little water, cover.\nStew on low 15-20 min until tender; season.', 'ru': 'Обжарьте говядину кубиками на сильном огне 4–5 мин до корочки.\nДобавьте лук и морковь, готовьте 5 мин.\nДобавьте нарезанный помидор и немного воды, накройте.\nТушите на слабом огне 15–20 мин до мягкости; посолите.', 'uk': 'Обсмажте яловичину кубиками на сильному вогні 4–5 хв до скоринки.\nДодайте цибулю й моркву, готуйте 5 хв.\nДодайте нарізаний помідор і трохи води, накрийте.\nТушкуйте на слабкому вогні 15–20 хв до м’якості; посоліть.'},
  'recipe.beef_veg.multicooker': {'en': '"Fry" mode: brown the beef 6 min.\nAdd onion, carrot and tomato.\n"Stew" mode for 1 hour.\nRest 10 min.', 'ru': 'Режим «Жарка»: обжарьте говядину 6 мин.\nДобавьте лук, морковь и помидор.\nРежим «Тушение» 1 час.\nДайте настояться 10 мин.', 'uk': 'Режим «Смаження»: обсмажте яловичину 6 хв.\nДодайте цибулю, моркву й помідор.\nРежим «Тушкування» 1 година.\nДайте настоятися 10 хв.'},
  'recipe.beef_veg.flavor': {'en': 'Beef — rich protein and iron.\nTomato — a savoury sauce.\nCarrot — sweetness.\nOnion — aroma.', 'ru': 'Говядина — насыщенный белок и железо.\nПомидор — насыщенный соус.\nМорковь — сладость.\nЛук — аромат.', 'uk': 'Яловичина — насичений білок і залізо.\nПомідор — насичений соус.\nМорква — солодкість.\nЦибуля — аромат.'},
  'recipe.shrimp_salad.pan': {'en': 'Sear the shrimp on high 1-2 min per side, just until pink.\nChop the cucumber and tomato into a bowl.\nAdd the warm shrimp, drizzle with oil, season.\nTop with shaved cheese; serve right away.', 'ru': 'Обжарьте креветки на сильном огне 1–2 мин с каждой стороны до розового цвета.\nНарежьте огурец и помидор в миску.\nДобавьте тёплые креветки, сбрызните маслом, посолите.\nПосыпьте стружкой сыра; подавайте сразу.', 'uk': 'Обсмажте креветки на сильному вогні 1–2 хв з кожного боку до рожевого кольору.\nНаріжте огірок і помідор у миску.\nДодайте теплі креветки, збризніть олією, посоліть.\nПосипте стружкою сиру; подавайте одразу.'},
  'recipe.shrimp_salad.flavor': {'en': 'Shrimp — lean protein, cooks in minutes.\nCucumber and tomato — freshness and crunch.\nCheese — a salty accent.', 'ru': 'Креветки — постный белок, готовятся за минуты.\nОгурец и помидор — свежесть и хруст.\nСыр — солёный акцент.', 'uk': 'Креветки — пісний білок, готуються за хвилини.\nОгірок і помідор — свіжість і хрускіт.\nСир — солоний акцент.'},
  'recipe.cottage_berries.assembly': {'en': 'Put the cottage cheese in a bowl.\nRinse the berries and add on top.\nOptional: a spoon of honey or yogurt.', 'ru': 'Выложите творог в миску.\nОполосните ягоды и выложите сверху.\nПо желанию — ложка мёда или йогурта.', 'uk': 'Викладіть сир у миску.\nСполосніть ягоди й викладіть зверху.\nЗа бажанням — ложка меду або йогурту.'},
  'recipe.cottage_berries.flavor': {'en': 'Cottage cheese — protein.\nBerries — antioxidants and natural sweetness.', 'ru': 'Творог — белок.\nЯгоды — антиоксиданты и натуральная сладость.', 'uk': 'Сир — білок.\nЯгоди — антиоксиданти і натуральна солодкість.'},
  'recipe.kefir_snack.assembly': {'en': 'Shake the kefir well.\nPour into a glass.\nOptional: a pinch of cinnamon or a few berries.', 'ru': 'Хорошо взболтайте кефир.\nНалейте в стакан.\nПо желанию — щепотка корицы или немного ягод.', 'uk': 'Добре збовтайте кефір.\nНалийте у склянку.\nЗа бажанням — дрібка кориці або трохи ягід.'},
  'recipe.kefir_snack.flavor': {'en': 'Kefir — protein and gut-friendly probiotics.', 'ru': 'Кефир — белок и полезные для кишечника пробиотики.', 'uk': 'Кефір — білок і корисні для кишківника пробіотики.'},
  'recipe.eggs_toast.pan': {'en': 'Toast the bread and top with sliced cheese.\nFry the eggs on medium to your liking (3-4 min).\nSlide the eggs onto the toast, add sliced tomato.', 'ru': 'Подрумяньте хлеб и положите ломтики сыра.\nПожарьте яйца на среднем огне по вкусу (3–4 мин).\nВыложите яйца на тост, добавьте нарезанный помидор.', 'uk': 'Підрум’яньте хліб і покладіть скибочки сиру.\nПосмажте яйця на середньому вогні до смаку (3–4 хв).\nВикладіть яйця на тост, додайте нарізаний помідор.'},
  'recipe.eggs_toast.flavor': {'en': 'Eggs — protein.\nBread — energy.\nCheese — savoury richness.\nTomato — freshness.', 'ru': 'Яйца — белок.\nХлеб — энергия.\nСыр — солёная сытость.\nПомидор — свежесть.', 'uk': 'Яйця — білок.\nХліб — енергія.\nСир — солона ситість.\nПомідор — свіжість.'},
  'recipe.rice_milk.pot': {'en': 'Bring milk to a gentle simmer.\nAdd rinsed rice, cook on low 18-20 min, stirring.\nStir in honey off the heat; top with walnuts.', 'ru': 'Доведите молоко до лёгкого кипения.\nДобавьте промытый рис, варите на слабом огне 18–20 мин, помешивая.\nВмешайте мёд вне огня; посыпьте орехами.', 'uk': 'Доведіть молоко до легкого кипіння.\nДодайте промитий рис, варіть на слабкому вогні 18–20 хв, помішуючи.\nВмішайте мед поза вогнем; посипте горіхами.'},
  'recipe.rice_milk.flavor': {'en': 'Rice — comforting carbs.\nMilk — creaminess and protein.\nHoney — sweetness.\nWalnuts — crunch and fats.', 'ru': 'Рис — уютные углеводы.\nМолоко — кремовость и белок.\nМёд — сладость.\nОрехи — хруст и жиры.', 'uk': 'Рис — затишні вуглеводи.\nМолоко — кремовість і білок.\nМед — солодкість.\nГоріхи — хрускіт і жири.'},
  'recipe.fruit_yogurt.assembly': {'en': 'Spoon yogurt into a bowl.\nAdd sliced apple and banana.\nSprinkle oats on top.', 'ru': 'Выложите йогурт в миску.\nДобавьте нарезанные яблоко и банан.\nПосыпьте овсянкой.', 'uk': 'Викладіть йогурт у миску.\nДодайте нарізані яблуко й банан.\nПосипте вівсянкою.'},
  'recipe.fruit_yogurt.flavor': {'en': 'Yogurt — protein and probiotics.\nFruit — natural sweetness and vitamins.\nOats — fibre and staying power.', 'ru': 'Йогурт — белок и пробиотики.\nФрукты — натуральная сладость и витамины.\nОвсянка — клетчатка и сытость.', 'uk': 'Йогурт — білок і пробіотики.\nФрукти — натуральна солодкість і вітаміни.\nВівсянка — клітковина і ситість.'},
  'recipe.cheese_omelette.pan': {'en': 'Whisk eggs with milk and a pinch of salt.\nPour into a buttered pan on medium, cook covered 3-4 min.\nScatter cheese, fold, remove after 1 min.', 'ru': 'Взбейте яйца с молоком и щепоткой соли.\nВылейте на смазанную сковороду на среднем огне, готовьте под крышкой 3–4 мин.\nПосыпьте сыром, сложите, снимите через 1 мин.', 'uk': 'Збийте яйця з молоком і дрібкою солі.\nВилийте на змащену сковороду на середньому вогні, готуйте під кришкою 3–4 хв.\nПосипте сиром, складіть, зніміть за 1 хв.'},
  'recipe.cheese_omelette.flavor': {'en': 'Eggs — protein.\nCheese — creamy, savoury richness.\nMilk — a tender texture.', 'ru': 'Яйца — белок.\nСыр — сливочная солёная сытость.\nМолоко — нежная текстура.', 'uk': 'Яйця — білок.\nСир — вершкова солона ситість.\nМолоко — ніжна текстура.'},
  'recipe.beef_buckwheat.pot': {'en': 'Cook buckwheat 1:2 in water 15 min covered.\nSauté onion and carrot 5 min, add diced beef, brown 8 min.\nCombine with the buckwheat, cover, warm 3 min.', 'ru': 'Сварите гречку 1:2 в воде 15 мин под крышкой.\nОбжарьте лук и морковь 5 мин, добавьте говядину кубиками, обжарьте 8 мин.\nСоедините с гречкой, накройте, прогрейте 3 мин.', 'uk': 'Зваріть гречку 1:2 у воді 15 хв під кришкою.\nОбсмажте цибулю й моркву 5 хв, додайте яловичину кубиками, обсмажте 8 хв.\nЗ’єднайте з гречкою, накрийте, прогрійте 3 хв.'},
  'recipe.beef_buckwheat.flavor': {'en': 'Beef — protein and iron.\nBuckwheat — slow carbs.\nCarrot and onion — the aromatic base.', 'ru': 'Говядина — белок и железо.\nГречка — медленные углеводы.\nМорковь и лук — ароматная база.', 'uk': 'Яловичина — білок і залізо.\nГречка — повільні вуглеводи.\nМорква й цибуля — ароматна база.'},
  'recipe.fish_potatoes.oven': {'en': 'Heat the oven to 200 °C.\nCut potatoes into wedges, toss with oil and salt.\nAdd the seasoned fish, bake together 25 min.', 'ru': 'Разогрейте духовку до 200 °C.\nНарежьте картофель дольками, перемешайте с маслом и солью.\nДобавьте приправленную рыбу, запекайте вместе 25 мин.', 'uk': 'Розігрійте духовку до 200 °C.\nНаріжте картоплю часточками, перемішайте з олією й сіллю.\nДодайте приправлену рибу, запікайте разом 25 хв.'},
  'recipe.fish_potatoes.flavor': {'en': 'Fish — protein and omega-3.\nPotatoes — heartiness.\nCarrot and onion — flavour.', 'ru': 'Рыба — белок и омега-3.\nКартофель — сытность.\nМорковь и лук — вкус.', 'uk': 'Риба — білок і омега-3.\nКартопля — ситність.\nМорква й цибуля — смак.'},
  'recipe.chicken_rice_veg.pan': {'en': 'Boil the rice 12-15 min, drain.\nPan-fry diced chicken 8 min until golden.\nAdd carrot and tomato, cook 4 min; fold in the rice.', 'ru': 'Отварите рис 12–15 мин, слейте.\nОбжарьте курицу кубиками 8 мин до золотистости.\nДобавьте морковь и помидор, готовьте 4 мин; вмешайте рис.', 'uk': 'Відваріть рис 12–15 хв, злийте.\nОбсмажте курку кубиками 8 хв до золотистості.\nДодайте моркву й помідор, готуйте 4 хв; вмішайте рис.'},
  'recipe.chicken_rice_veg.flavor': {'en': 'Chicken — lean protein.\nRice — energy.\nCarrot and tomato — colour and vitamins.', 'ru': 'Курица — постный белок.\nРис — энергия.\nМорковь и помидор — цвет и витамины.', 'uk': 'Курка — пісний білок.\nРис — енергія.\nМорква й помідор — колір і вітаміни.'},
  'recipe.shrimp_pasta.pan': {'en': 'Boil the pasta 8-10 min, drain.\nSear the shrimp 1-2 min per side, add chopped tomato 2 min.\nToss in the pasta, finish with cheese.', 'ru': 'Отварите пасту 8–10 мин, слейте.\nОбжарьте креветки 1–2 мин с каждой стороны, добавьте помидор на 2 мин.\nВмешайте пасту, завершите сыром.', 'uk': 'Відваріть пасту 8–10 хв, злийте.\nОбсмажте креветки 1–2 хв з кожного боку, додайте помідор на 2 хв.\nВмішайте пасту, завершіть сиром.'},
  'recipe.shrimp_pasta.flavor': {'en': 'Shrimp — quick lean protein.\nPasta — the base.\nTomato — light sauce.\nCheese — savoury finish.', 'ru': 'Креветки — быстрый постный белок.\nПаста — основа.\nПомидор — лёгкий соус.\nСыр — солёный акцент.', 'uk': 'Креветки — швидкий пісний білок.\nПаста — основа.\nПомідор — легкий соус.\nСир — солоний акцент.'},
  'recipe.chicken_veg_stew.pot': {'en': 'Sauté onion and carrot 5 min.\nAdd diced chicken, brown 6 min.\nAdd diced potato and water, stew covered 20 min; season.', 'ru': 'Обжарьте лук и морковь 5 мин.\nДобавьте курицу кубиками, обжарьте 6 мин.\nДобавьте картофель кубиками и воду, тушите под крышкой 20 мин; посолите.', 'uk': 'Обсмажте цибулю й моркву 5 хв.\nДодайте курку кубиками, обсмажте 6 хв.\nДодайте картоплю кубиками й воду, тушкуйте під кришкою 20 хв; посоліть.'},
  'recipe.chicken_veg_stew.flavor': {'en': 'Chicken — protein.\nPotato — heartiness.\nCarrot — sweetness.\nOnion — aroma.', 'ru': 'Курица — белок.\nКартофель — сытность.\nМорковь — сладость.\nЛук — аромат.', 'uk': 'Курка — білок.\nКартопля — ситність.\nМорква — солодкість.\nЦибуля — аромат.'},
  'recipe.fish_fresh_salad.pan': {'en': 'Pan-fry the fish 3-4 min per side.\nChop cucumber and tomato, dress with oil and salt.\nServe the fish over the salad, top with cheese.', 'ru': 'Обжарьте рыбу 3–4 мин с каждой стороны.\nНарежьте огурец и помидор, заправьте маслом и солью.\nПодайте рыбу на салате, посыпьте сыром.', 'uk': 'Обсмажте рибу 3–4 хв з кожного боку.\nНаріжте огірок і помідор, заправте олією й сіллю.\nПодайте рибу на салаті, посипте сиром.'},
  'recipe.fish_fresh_salad.flavor': {'en': 'Fish — protein and omega-3.\nCucumber and tomato — freshness.\nCheese — a salty accent.', 'ru': 'Рыба — белок и омега-3.\nОгурец и помидор — свежесть.\nСыр — солёный акцент.', 'uk': 'Риба — білок і омега-3.\nОгірок і помідор — свіжість.\nСир — солоний акцент.'},
  'recipe.beef_lentils.pot': {'en': 'Rinse the lentils.\nBrown the diced beef 5 min, add onion and carrot 5 min.\nAdd lentils and water, simmer 25 min until soft; season.', 'ru': 'Промойте чечевицу.\nОбжарьте говядину кубиками 5 мин, добавьте лук и морковь на 5 мин.\nДобавьте чечевицу и воду, варите 25 мин до мягкости; посолите.', 'uk': 'Промийте сочевицю.\nОбсмажте яловичину кубиками 5 хв, додайте цибулю й моркву на 5 хв.\nДодайте сочевицю й воду, варіть 25 хв до м’якості; посоліть.'},
  'recipe.beef_lentils.flavor': {'en': 'Beef — protein and iron.\nLentils — plant protein and fibre.\nCarrot and onion — the base.', 'ru': 'Говядина — белок и железо.\nЧечевица — растительный белок и клетчатка.\nМорковь и лук — база.', 'uk': 'Яловичина — білок і залізо.\nСочевиця — рослинний білок і клітковина.\nМорква й цибуля — база.'},
  'recipe.egg_potato_bake.oven': {'en': 'Heat the oven to 190 °C.\nSlice boiled potato into a dish, pour over beaten eggs.\nTop with tomato and cheese, bake 20 min.', 'ru': 'Разогрейте духовку до 190 °C.\nНарежьте варёный картофель в форму, залейте взбитыми яйцами.\nСверху помидор и сыр, запекайте 20 мин.', 'uk': 'Розігрійте духовку до 190 °C.\nНаріжте варену картоплю у форму, залийте збитими яйцями.\nЗверху помідор і сир, запікайте 20 хв.'},
  'recipe.egg_potato_bake.flavor': {'en': 'Eggs — protein and binding.\nPotato — heartiness.\nTomato — juiciness.\nCheese — a golden top.', 'ru': 'Яйца — белок и связка.\nКартофель — сытность.\nПомидор — сочность.\nСыр — румяная корочка.', 'uk': 'Яйця — білок і зв’язка.\nКартопля — ситність.\nПомідор — соковитість.\nСир — рум’яна скоринка.'},
  'recipe.nuts_banana.assembly': {'en': 'Slice the banana.\nScatter chopped walnuts on top.', 'ru': 'Нарежьте банан.\nПосыпьте рублеными орехами.', 'uk': 'Наріжте банан.\nПосипте рубленими горіхами.'},
  'recipe.nuts_banana.flavor': {'en': 'Banana — quick energy.\nWalnuts — healthy fats and crunch.', 'ru': 'Банан — быстрая энергия.\nОрехи — полезные жиры и хруст.', 'uk': 'Банан — швидка енергія.\nГоріхи — корисні жири і хрускіт.'},
  'recipe.bread_cheese.assembly': {'en': 'Slice the bread.\nTop with cheese; toast lightly if you like.', 'ru': 'Нарежьте хлеб.\nПоложите сыр; по желанию слегка подрумяньте.', 'uk': 'Наріжте хліб.\nПокладіть сир; за бажанням злегка підрум’яньте.'},
  'recipe.bread_cheese.flavor': {'en': 'Bread — energy.\nCheese — protein and a savoury taste.', 'ru': 'Хлеб — энергия.\nСыр — белок и солёный вкус.', 'uk': 'Хліб — енергія.\nСир — білок і солоний смак.'},
  'recipe.yogurt_berries.assembly': {'en': 'Spoon yogurt into a glass.\nAdd rinsed berries on top.', 'ru': 'Выложите йогурт в стакан.\nДобавьте промытые ягоды.', 'uk': 'Викладіть йогурт у склянку.\nДодайте промиті ягоди.'},
  'recipe.yogurt_berries.flavor': {'en': 'Yogurt — protein and probiotics.\nBerries — antioxidants and sweetness.', 'ru': 'Йогурт — белок и пробиотики.\nЯгоды — антиоксиданты и сладость.', 'uk': 'Йогурт — білок і пробіотики.\nЯгоди — антиоксиданти і солодкість.'},
  'recipe.mushroom_omelette.pan': {'en': 'Slice mushrooms and onion; sauté on medium 5 min until dry.\nPour in beaten eggs, cook covered 3-4 min.\nScatter cheese, fold, rest 1 min.', 'ru': 'Нарежьте грибы и лук; обжарьте на среднем огне 5 мин до сухости.\nВлейте взбитые яйца, готовьте под крышкой 3–4 мин.\nПосыпьте сыром, сложите, дайте постоять 1 мин.', 'uk': 'Наріжте гриби й цибулю; обсмажте на середньому вогні 5 хв до сухості.\nВлийте збиті яйця, готуйте під кришкою 3–4 хв.\nПосипте сиром, складіть, дайте постояти 1 хв.'},
  'recipe.mushroom_omelette.flavor': {'en': 'Eggs — protein.\nMushrooms — savoury umami.\nCheese — richness.\nOnion — aroma.', 'ru': 'Яйца — белок.\nГрибы — умами.\nСыр — сытость.\nЛук — аромат.', 'uk': 'Яйця — білок.\nГриби — умамі.\nСир — ситість.\nЦибуля — аромат.'},
  'recipe.cottage_oats.assembly': {'en': 'Mix cottage cheese with the oats.\nAdd sliced banana and honey.\nBest after 5 min so the oats soften.', 'ru': 'Смешайте творог с овсянкой.\nДобавьте нарезанный банан и мёд.\nЛучше через 5 мин, чтобы овсянка размякла.', 'uk': 'Змішайте сир з вівсянкою.\nДодайте нарізаний банан і мед.\nКраще за 5 хв, щоб вівсянка розм’якла.'},
  'recipe.cottage_oats.flavor': {'en': 'Cottage cheese — protein.\nOats — fibre.\nBanana and honey — natural sweetness.', 'ru': 'Творог — белок.\nОвсянка — клетчатка.\nБанан и мёд — натуральная сладость.', 'uk': 'Сир — білок.\nВівсянка — клітковина.\nБанан і мед — натуральна солодкість.'},
  'recipe.veggie_toast.pan': {'en': 'Toast the bread in a dry pan.\nTop with cheese and let it melt under a lid 1 min.\nAdd sliced tomato and bell pepper.', 'ru': 'Подрумяньте хлеб на сухой сковороде.\nПоложите сыр и дайте расплавиться под крышкой 1 мин.\nДобавьте нарезанные помидор и перец.', 'uk': 'Підрум’яньте хліб на сухій сковороді.\nПокладіть сир і дайте розплавитися під кришкою 1 хв.\nДодайте нарізані помідор і перець.'},
  'recipe.veggie_toast.flavor': {'en': 'Bread — energy.\nCheese — protein and melt.\nTomato and pepper — freshness and vitamins.', 'ru': 'Хлеб — энергия.\nСыр — белок и тягучесть.\nПомидор и перец — свежесть и витамины.', 'uk': 'Хліб — енергія.\nСир — білок і тягучість.\nПомідор і перець — свіжість і вітаміни.'},
  'recipe.turkey_buckwheat.pot': {'en': 'Cook buckwheat 1:2 in water 15 min covered.\nSauté onion and carrot 5 min, add diced turkey, cook 8 min.\nCombine with the buckwheat, warm 3 min.', 'ru': 'Сварите гречку 1:2 в воде 15 мин под крышкой.\nОбжарьте лук и морковь 5 мин, добавьте индейку кубиками, готовьте 8 мин.\nСоедините с гречкой, прогрейте 3 мин.', 'uk': 'Зваріть гречку 1:2 у воді 15 хв під кришкою.\nОбсмажте цибулю й моркву 5 хв, додайте індичку кубиками, готуйте 8 хв.\nЗ’єднайте з гречкою, прогрійте 3 хв.'},
  'recipe.turkey_buckwheat.flavor': {'en': 'Turkey — very lean protein.\nBuckwheat — slow carbs and iron.\nCarrot and onion — the base.', 'ru': 'Индейка — очень постный белок.\nГречка — медленные углеводы и железо.\nМорковь и лук — база.', 'uk': 'Індичка — дуже пісний білок.\nГречка — повільні вуглеводи й залізо.\nМорква й цибуля — база.'},
  'recipe.veggie_stew.pot': {'en': 'Dice all the vegetables.\nSauté carrot and pepper 5 min, add potato and zucchini.\nAdd a little water, stew covered 20 min; season.', 'ru': 'Нарежьте все овощи кубиками.\nОбжарьте морковь и перец 5 мин, добавьте картофель и кабачок.\nДобавьте немного воды, тушите под крышкой 20 мин; посолите.', 'uk': 'Наріжте всі овочі кубиками.\nОбсмажте моркву й перець 5 хв, додайте картоплю й кабачок.\nДодайте трохи води, тушкуйте під кришкою 20 хв; посоліть.'},
  'recipe.veggie_stew.flavor': {'en': 'Potato — heartiness.\nZucchini — light texture.\nPepper and carrot — sweetness and vitamins.', 'ru': 'Картофель — сытность.\nКабачок — лёгкая текстура.\nПерец и морковь — сладость и витамины.', 'uk': 'Картопля — ситність.\nКабачок — легка текстура.\nПерець і морква — солодкість і вітаміни.'},
  'recipe.chicken_pasta_veg.pan': {'en': 'Boil the pasta 8-10 min, drain.\nFry diced chicken 8 min, add diced zucchini and tomato 4 min.\nToss in the pasta with a splash of the water.', 'ru': 'Отварите пасту 8–10 мин, слейте.\nОбжарьте курицу кубиками 8 мин, добавьте кабачок и помидор на 4 мин.\nВмешайте пасту с ложкой воды.', 'uk': 'Відваріть пасту 8–10 хв, злийте.\nОбсмажте курку кубиками 8 хв, додайте кабачок і помідор на 4 хв.\nВмішайте пасту з ложкою води.'},
  'recipe.chicken_pasta_veg.flavor': {'en': 'Chicken — lean protein.\nPasta — the base.\nZucchini and tomato — a light vegetable sauce.', 'ru': 'Курица — постный белок.\nПаста — основа.\nКабачок и помидор — лёгкий овощной соус.', 'uk': 'Курка — пісний білок.\nПаста — основа.\nКабачок і помідор — легкий овочевий соус.'},
  'recipe.fish_rice_veg.pan': {'en': 'Boil the rice 12-15 min; add peas for the last 3 min.\nPan-fry the fish 3-4 min per side.\nGrate carrot in raw or steam briefly; plate together.', 'ru': 'Отварите рис 12–15 мин; за 3 мин до конца добавьте горошек.\nОбжарьте рыбу 3–4 мин с каждой стороны.\nМорковь натрите сырой или припустите; подайте вместе.', 'uk': 'Відваріть рис 12–15 хв; за 3 хв до кінця додайте горошок.\nОбсмажте рибу 3–4 хв з кожного боку.\nМоркву натріть сирою або припустіть; подайте разом.'},
  'recipe.fish_rice_veg.flavor': {'en': 'Fish — protein and omega-3.\nRice and peas — energy and fibre.\nCarrot — sweetness.', 'ru': 'Рыба — белок и омега-3.\nРис и горошек — энергия и клетчатка.\nМорковь — сладость.', 'uk': 'Риба — білок і омега-3.\nРис і горошок — енергія і клітковина.\nМорква — солодкість.'},
  'recipe.turkey_salad.pan': {'en': 'Sear diced turkey on high 6-7 min until cooked through.\nChop cucumber and tomato into a bowl.\nAdd the warm turkey, oil and salt; top with cheese.', 'ru': 'Обжарьте индейку кубиками на сильном огне 6–7 мин до готовности.\nНарежьте огурец и помидор в миску.\nДобавьте тёплую индейку, масло и соль; посыпьте сыром.', 'uk': 'Обсмажте індичку кубиками на сильному вогні 6–7 хв до готовності.\nНаріжте огірок і помідор у миску.\nДодайте теплу індичку, олію й сіль; посипте сиром.'},
  'recipe.turkey_salad.flavor': {'en': 'Turkey — very lean protein.\nCucumber and tomato — freshness.\nCheese — a salty accent.', 'ru': 'Индейка — очень постный белок.\nОгурец и помидор — свежесть.\nСыр — солёный акцент.', 'uk': 'Індичка — дуже пісний білок.\nОгірок і помідор — свіжість.\nСир — солоний акцент.'},
  'recipe.mushroom_chicken.pan': {'en': 'Brown diced chicken on medium 8 min.\nAdd sliced mushrooms and onion, cook 6 min until dry.\nOff the heat, scatter cheese and cover 1 min.', 'ru': 'Обжарьте курицу кубиками на среднем огне 8 мин.\nДобавьте грибы и лук, готовьте 6 мин до сухости.\nВне огня посыпьте сыром и накройте на 1 мин.', 'uk': 'Обсмажте курку кубиками на середньому вогні 8 хв.\nДодайте гриби й цибулю, готуйте 6 хв до сухості.\nПоза вогнем посипте сиром і накрийте на 1 хв.'},
  'recipe.mushroom_chicken.flavor': {'en': 'Chicken — protein.\nMushrooms — umami depth.\nCheese — creamy finish.\nOnion — aroma.', 'ru': 'Курица — белок.\nГрибы — глубина умами.\nСыр — сливочный акцент.\nЛук — аромат.', 'uk': 'Курка — білок.\nГриби — глибина умамі.\nСир — вершковий акцент.\nЦибуля — аромат.'},
  'recipe.stuffed_peppers.oven': {'en': 'Heat the oven to 190 °C.\nMix minced beef with half-cooked rice and chopped tomato.\nHalve and core the peppers, fill them, bake 30-35 min.', 'ru': 'Разогрейте духовку до 190 °C.\nСмешайте фарш с полуготовым рисом и нарезанным помидором.\nРазрежьте перцы, очистите, наполните, запекайте 30–35 мин.', 'uk': 'Розігрійте духовку до 190 °C.\nЗмішайте фарш з напівготовим рисом і нарізаним помідором.\nРозріжте перці, очистіть, наповніть, запікайте 30–35 хв.'},
  'recipe.stuffed_peppers.flavor': {'en': 'Bell pepper — sweet, juicy shell.\nBeef — protein.\nRice — the filling base.\nTomato — moisture.', 'ru': 'Перец — сладкая сочная оболочка.\nГовядина — белок.\nРис — основа начинки.\nПомидор — сочность.', 'uk': 'Перець — солодка соковита оболонка.\nЯловичина — білок.\nРис — основа начинки.\nПомідор — соковитість.'},
  'recipe.zucchini_eggs.pan': {'en': 'Slice zucchini thin, sauté on medium 5 min.\nPour in beaten eggs, cook covered 4 min.\nAdd tomato and cheese, cover 1 min more.', 'ru': 'Нарежьте кабачок тонко, обжарьте на среднем огне 5 мин.\nВлейте взбитые яйца, готовьте под крышкой 4 мин.\nДобавьте помидор и сыр, накройте ещё на 1 мин.', 'uk': 'Наріжте кабачок тонко, обсмажте на середньому вогні 5 хв.\nВлийте збиті яйця, готуйте під кришкою 4 хв.\nДодайте помідор і сир, накрийте ще на 1 хв.'},
  'recipe.zucchini_eggs.flavor': {'en': 'Zucchini — light, low-carb bulk.\nEggs — protein.\nCheese — richness.\nTomato — freshness.', 'ru': 'Кабачок — лёгкий низкоуглеводный объём.\nЯйца — белок.\nСыр — сытость.\nПомидор — свежесть.', 'uk': 'Кабачок — легкий низьковуглеводний об’єм.\nЯйця — білок.\nСир — ситість.\nПомідор — свіжість.'},
  'recipe.cottage_cucumber.assembly': {'en': 'Put the cottage cheese in a bowl.\nDice the cucumber and stir in.\nSeason with salt or herbs.', 'ru': 'Выложите творог в миску.\nНарежьте огурец и вмешайте.\nПосолите или добавьте зелень.', 'uk': 'Викладіть сир у миску.\nНаріжте огірок і вмішайте.\nПосоліть або додайте зелень.'},
  'recipe.cottage_cucumber.flavor': {'en': 'Cottage cheese — lean protein.\nCucumber — freshness and crunch.', 'ru': 'Творог — постный белок.\nОгурец — свежесть и хруст.', 'uk': 'Сир — пісний білок.\nОгірок — свіжість і хрускіт.'},
  'recipe.apple_banana.assembly': {'en': 'Slice the apple and banana.\nServe together — a quick energy snack.', 'ru': 'Нарежьте яблоко и банан.\nПодавайте вместе — быстрый перекус для энергии.', 'uk': 'Наріжте яблуко й банан.\nПодавайте разом — швидкий перекус для енергії.'},
  'recipe.apple_banana.flavor': {'en': 'Apple — fibre and crunch.\nBanana — quick energy and potassium.', 'ru': 'Яблоко — клетчатка и хруст.\nБанан — быстрая энергия и калий.', 'uk': 'Яблуко — клітковина і хрускіт.\nБанан — швидка енергія і калій.'},
  'recipe.boiled_eggs.pot': {'en': 'Lower eggs into boiling water.\nBoil 7 min for medium, 9-10 for hard.\nCool under cold water, then peel.', 'ru': 'Опустите яйца в кипящую воду.\nВарите 7 мин для средних, 9–10 для крутых.\nОстудите под холодной водой, очистите.', 'uk': 'Опустіть яйця в окріп.\nВаріть 7 хв для середніх, 9–10 для крутих.\nОстудіть під холодною водою, очистіть.'},
  'recipe.boiled_eggs.flavor': {'en': 'Eggs — complete protein, minimal carbs — an easy filling snack.', 'ru': 'Яйца — полноценный белок, минимум углеводов — простой сытный перекус.', 'uk': 'Яйця — повноцінний білок, мінімум вуглеводів — простий ситний перекус.'},
  'recipe.kefir_berries.assembly': {'en': 'Pour the kefir into a glass.\nAdd rinsed berries; stir or leave layered.', 'ru': 'Налейте кефир в стакан.\nДобавьте промытые ягоды; размешайте или оставьте слоями.', 'uk': 'Налийте кефір у склянку.\nДодайте промиті ягоди; розмішайте або залиште шарами.'},
  'recipe.kefir_berries.flavor': {'en': 'Kefir — protein and probiotics.\nBerries — antioxidants and natural sweetness.', 'ru': 'Кефир — белок и пробиотики.\nЯгоды — антиоксиданты и натуральная сладость.', 'uk': 'Кефір — білок і пробіотики.\nЯгоди — антиоксиданти і натуральна солодкість.'},
  'recipe.spinach_eggs.pan': {'en': 'Wilt the spinach on medium 1-2 min.\nPour in beaten eggs, cook gently 3 min.\nAdd tomato and cheese, cover 1 min.', 'ru': 'Припустите шпинат на среднем огне 1–2 мин.\nВлейте взбитые яйца, готовьте аккуратно 3 мин.\nДобавьте помидор и сыр, накройте на 1 мин.', 'uk': 'Припустіть шпинат на середньому вогні 1–2 хв.\nВлийте збиті яйця, готуйте обережно 3 хв.\nДодайте помідор і сир, накрийте на 1 хв.'},
  'recipe.spinach_eggs.flavor': {'en': 'Eggs — protein.\nSpinach — iron and folate.\nCheese — richness.\nTomato — freshness.', 'ru': 'Яйца — белок.\nШпинат — железо и фолаты.\nСыр — сытость.\nПомидор — свежесть.', 'uk': 'Яйця — білок.\nШпинат — залізо й фолати.\nСир — ситість.\nПомідор — свіжість.'},
  'recipe.berry_smoothie.assembly': {'en': 'Put milk, banana, berries and oats in a blender.\nBlend 30-40 sec until smooth.\nDrink fresh; add a little water if too thick.', 'ru': 'Положите в блендер молоко, банан, ягоды и овсянку.\nВзбейте 30–40 сек до однородности.\nПейте свежим; добавьте воды, если густо.', 'uk': 'Покладіть у блендер молоко, банан, ягоди й вівсянку.\nЗбийте 30–40 сек до однорідності.\nПийте свіжим; додайте води, якщо густо.'},
  'recipe.berry_smoothie.flavor': {'en': 'Milk — protein and creaminess.\nBanana — sweetness and body.\nBerries — antioxidants.\nOats — fibre.', 'ru': 'Молоко — белок и кремовость.\nБанан — сладость и плотность.\nЯгоды — антиоксиданты.\nОвсянка — клетчатка.', 'uk': 'Молоко — білок і кремовість.\nБанан — солодкість і щільність.\nЯгоди — антиоксиданти.\nВівсянка — клітковина.'},
  'recipe.banana_pancakes.pan': {'en': 'Mash the banana, mix with eggs, oats and milk.\nCook small pancakes on medium 2-3 min per side.\nServe warm, optionally with berries.', 'ru': 'Разомните банан, смешайте с яйцами, овсянкой и молоком.\nЖарьте небольшие панкейки на среднем огне 2–3 мин с каждой стороны.\nПодавайте тёплыми, по желанию с ягодами.', 'uk': 'Розімніть банан, змішайте з яйцями, вівсянкою й молоком.\nСмажте невеликі панкейки на середньому вогні 2–3 хв з кожного боку.\nПодавайте теплими, за бажанням з ягодами.'},
  'recipe.banana_pancakes.flavor': {'en': 'Banana — natural sweetness, no added sugar.\nEggs — protein and binding.\nOats — fibre and structure.', 'ru': 'Банан — натуральная сладость без сахара.\nЯйца — белок и связка.\nОвсянка — клетчатка и структура.', 'uk': 'Банан — натуральна солодкість без цукру.\nЯйця — білок і зв’язка.\nВівсянка — клітковина і структура.'},
  'recipe.salmon_rice.oven': {'en': 'Heat the oven to 200 °C.\nSalt the salmon, drizzle with oil and lemon; bake 15 min.\nBoil the rice; steam the broccoli and carrot 5-6 min. Plate together.', 'ru': 'Разогрейте духовку до 200 °C.\nПосолите лосось, сбрызните маслом и лимоном; запекайте 15 мин.\nОтварите рис; припустите брокколи и морковь 5–6 мин. Подайте вместе.', 'uk': 'Розігрійте духовку до 200 °C.\nПосоліть лосось, збризніть олією й лимоном; запікайте 15 хв.\nВідваріть рис; припустіть броколі й моркву 5–6 хв. Подайте разом.'},
  'recipe.salmon_rice.flavor': {'en': 'Salmon — protein and omega-3.\nRice — energy.\nBroccoli and carrot — fibre and vitamins.', 'ru': 'Лосось — белок и омега-3.\nРис — энергия.\nБрокколи и морковь — клетчатка и витамины.', 'uk': 'Лосось — білок і омега-3.\nРис — енергія.\nБроколі й морква — клітковина й вітаміни.'},
  'recipe.chickpea_stew.pot': {'en': 'Sauté onion and carrot 5 min.\nAdd chopped tomato, cook 3 min.\nAdd chickpeas and a little water, simmer 15 min; season.', 'ru': 'Обжарьте лук и морковь 5 мин.\nДобавьте нарезанный помидор, готовьте 3 мин.\nДобавьте нут и немного воды, тушите 15 мин; посолите.', 'uk': 'Обсмажте цибулю й моркву 5 хв.\nДодайте нарізаний помідор, готуйте 3 хв.\nДодайте нут і трохи води, тушкуйте 15 хв; посоліть.'},
  'recipe.chickpea_stew.flavor': {'en': 'Chickpeas — plant protein and fibre.\nTomato — a savoury base.\nCarrot and onion — aroma and sweetness.', 'ru': 'Нут — растительный белок и клетчатка.\nПомидор — насыщенная база.\nМорковь и лук — аромат и сладость.', 'uk': 'Нут — рослинний білок і клітковина.\nПомідор — насичена база.\nМорква й цибуля — аромат і солодкість.'},
  'recipe.turkey_potatoes.oven': {'en': 'Heat the oven to 200 °C.\nCut potatoes into wedges, toss with oil and salt.\nAdd the seasoned turkey pieces, bake together 30 min.', 'ru': 'Разогрейте духовку до 200 °C.\nНарежьте картофель дольками, перемешайте с маслом и солью.\nДобавьте приправленные кусочки индейки, запекайте вместе 30 мин.', 'uk': 'Розігрійте духовку до 200 °C.\nНаріжте картоплю часточками, перемішайте з олією й сіллю.\nДодайте приправлені шматочки індички, запікайте разом 30 хв.'},
  'recipe.turkey_potatoes.flavor': {'en': 'Turkey — very lean protein.\nPotatoes — heartiness.\nCarrot and onion — flavour.', 'ru': 'Индейка — очень постный белок.\nКартофель — сытность.\nМорковь и лук — вкус.', 'uk': 'Індичка — дуже пісний білок.\nКартопля — ситність.\nМорква й цибуля — смак.'},
  'recipe.tuna_pasta.pan': {'en': 'Boil the pasta 8-10 min, drain.\nSoften onion 3 min, add chopped tomato 3 min.\nStir in drained tuna and the pasta; warm 2 min.', 'ru': 'Отварите пасту 8–10 мин, слейте.\nОбжарьте лук 3 мин, добавьте помидор на 3 мин.\nВмешайте тунец без жидкости и пасту; прогрейте 2 мин.', 'uk': 'Відваріть пасту 8–10 хв, злийте.\nОбсмажте цибулю 3 хв, додайте помідор на 3 хв.\nВмішайте тунець без рідини й пасту; прогрійте 2 хв.'},
  'recipe.tuna_pasta.flavor': {'en': 'Tuna — lean protein, no cooking needed.\nPasta — the base.\nTomato and onion — a quick sauce.', 'ru': 'Тунец — постный белок, готовить не нужно.\nПаста — основа.\nПомидор и лук — быстрый соус.', 'uk': 'Тунець — пісний білок, готувати не треба.\nПаста — основа.\nПомідор і цибуля — швидкий соус.'},
  'recipe.salmon_salad.pan': {'en': 'Sear the salmon 3 min per side, flake into pieces.\nToss cucumber, tomato and spinach with oil.\nTop the salad with the warm salmon.', 'ru': 'Обжарьте лосось 3 мин с каждой стороны, разберите на кусочки.\nСмешайте огурец, помидор и шпинат с маслом.\nВыложите тёплый лосось на салат.', 'uk': 'Обсмажте лосось 3 хв з кожного боку, розберіть на шматочки.\nЗмішайте огірок, помідор і шпинат з олією.\nВикладіть теплий лосось на салат.'},
  'recipe.salmon_salad.flavor': {'en': 'Salmon — protein and omega-3.\nSpinach — iron.\nCucumber and tomato — freshness.', 'ru': 'Лосось — белок и омега-3.\nШпинат — железо.\nОгурец и помидор — свежесть.', 'uk': 'Лосось — білок і омега-3.\nШпинат — залізо.\nОгірок і помідор — свіжість.'},
  'recipe.broccoli_chicken.pan': {'en': 'Brown diced chicken on medium 8 min.\nAdd broccoli florets and onion, splash of water, cover 6 min.\nOff the heat, scatter cheese and cover 1 min.', 'ru': 'Обжарьте курицу кубиками на среднем огне 8 мин.\nДобавьте соцветия брокколи и лук, ложку воды, накройте на 6 мин.\nВне огня посыпьте сыром и накройте на 1 мин.', 'uk': 'Обсмажте курку кубиками на середньому вогні 8 хв.\nДодайте суцвіття броколі й цибулю, ложку води, накрийте на 6 хв.\nПоза вогнем посипте сиром і накрийте на 1 хв.'},
  'recipe.broccoli_chicken.flavor': {'en': 'Chicken — protein.\nBroccoli — fibre, vitamin C, low carb.\nCheese — a creamy finish.', 'ru': 'Курица — белок.\nБрокколи — клетчатка, витамин C, мало углеводов.\nСыр — сливочный акцент.', 'uk': 'Курка — білок.\nБроколі — клітковина, вітамін C, мало вуглеводів.\nСир — вершковий акцент.'},
  'recipe.beef_veg_grill.grill': {'en': 'Marinate beef and thick-cut vegetables 20 min (oil, salt, spices).\nGrill over medium heat, turning: beef 6-7 min, vegetables 8-10 min.\nRest the beef 5 min before slicing.', 'ru': 'Замаринуйте говядину и крупно нарезанные овощи 20 мин (масло, соль, специи).\nГотовьте на среднем жаре, переворачивая: говядина 6–7 мин, овощи 8–10 мин.\nДайте говядине отдохнуть 5 мин перед нарезкой.', 'uk': 'Замаринуйте яловичину й велико нарізані овочі 20 хв (олія, сіль, спеції).\nГотуйте на середньому жарі, перевертаючи: яловичина 6–7 хв, овочі 8–10 хв.\nДайте яловичині відпочити 5 хв перед нарізанням.'},
  'recipe.beef_veg_grill.flavor': {'en': 'Beef — protein and iron.\nZucchini and pepper — smoky, low-carb vegetables.\nOnion — sweetness on the grill.', 'ru': 'Говядина — белок и железо.\nКабачок и перец — овощи с дымком, мало углеводов.\nЛук — сладость на гриле.', 'uk': 'Яловичина — білок і залізо.\nКабачок і перець — овочі з димком, мало вуглеводів.\nЦибуля — солодкість на грилі.'},
  'recipe.chickpea_salad.assembly': {'en': 'Drain the chickpeas.\nDice cucumber and tomato, combine with the chickpeas.\nAdd crumbled cheese, oil and salt; toss.', 'ru': 'Слейте жидкость с нута.\nНарежьте огурец и помидор, соедините с нутом.\nДобавьте раскрошенный сыр, масло и соль; перемешайте.', 'uk': 'Злийте рідину з нуту.\nНаріжте огірок і помідор, з’єднайте з нутом.\nДодайте розкришений сир, олію й сіль; перемішайте.'},
  'recipe.chickpea_salad.flavor': {'en': 'Chickpeas — plant protein and fibre.\nCucumber and tomato — freshness.\nCheese — a savoury accent.', 'ru': 'Нут — растительный белок и клетчатка.\nОгурец и помидор — свежесть.\nСыр — солёный акцент.', 'uk': 'Нут — рослинний білок і клітковина.\nОгірок і помідор — свіжість.\nСир — солоний акцент.'},
  'recipe.tuna_snack.assembly': {'en': 'Drain the tuna.\nToast or slice the bread.\nSpread the tuna on top; add pepper if you like.', 'ru': 'Слейте жидкость с тунца.\nПодрумяньте или нарежьте хлеб.\nВыложите тунец сверху; по желанию поперчите.', 'uk': 'Злийте рідину з тунця.\nПідрум’яньте або наріжте хліб.\nВикладіть тунець зверху; за бажанням поперчіть.'},
  'recipe.tuna_snack.flavor': {'en': 'Tuna — lean protein.\nBread — energy and a base.', 'ru': 'Тунец — постный белок.\nХлеб — энергия и основа.', 'uk': 'Тунець — пісний білок.\nХліб — енергія й основа.'},
  'recipe.cheese_cubes.assembly': {'en': 'Cut the cheese into cubes.\nA quick, filling low-carb snack.', 'ru': 'Нарежьте сыр кубиками.\nБыстрый сытный низкоуглеводный перекус.', 'uk': 'Наріжте сир кубиками.\nШвидкий ситний низьковуглеводний перекус.'},
  'recipe.cheese_cubes.flavor': {'en': 'Cheese — protein, calcium and fats; very low in carbs.', 'ru': 'Сыр — белок, кальций и жиры; очень мало углеводов.', 'uk': 'Сир — білок, кальцій і жири; дуже мало вуглеводів.'},
  'recipe.berries_nuts.assembly': {'en': 'Rinse the berries into a bowl.\nScatter chopped walnuts on top.', 'ru': 'Промойте ягоды в миску.\nПосыпьте рублеными орехами.', 'uk': 'Промийте ягоди в миску.\nПосипте рубленими горіхами.'},
  'recipe.berries_nuts.flavor': {'en': 'Berries — antioxidants and low sugar.\nWalnuts — healthy fats and crunch.', 'ru': 'Ягоды — антиоксиданты и мало сахара.\nОрехи — полезные жиры и хруст.', 'uk': 'Ягоди — антиоксиданти й мало цукру.\nГоріхи — корисні жири і хрускіт.'},
  'recipe.apple_nuts.assembly': {'en': 'Slice the apple.\nServe with a handful of walnuts.', 'ru': 'Нарежьте яблоко.\nПодавайте с горстью орехов.', 'uk': 'Наріжте яблуко.\nПодавайте з жменею горіхів.'},
  'recipe.apple_nuts.flavor': {'en': 'Apple — fibre and freshness.\nWalnuts — healthy fats and staying power.', 'ru': 'Яблоко — клетчатка и свежесть.\nОрехи — полезные жиры и сытость.', 'uk': 'Яблуко — клітковина і свіжість.\nГоріхи — корисні жири і ситість.'},
  'recipe.avocado_toast.assembly': {'en': 'Boil the egg 7 min, cool and slice.\nToast the bread and mash the avocado on top.\nAdd sliced egg and tomato, season.', 'ru': 'Отварите яйцо 7 мин, остудите и нарежьте.\nПодрумяньте хлеб и разомните авокадо сверху.\nДобавьте нарезанные яйцо и помидор, посолите.', 'uk': 'Відваріть яйце 7 хв, остудіть і наріжте.\nПідрум’яньте хліб і розімніть авокадо зверху.\nДодайте нарізані яйце й помідор, посоліть.'},
  'recipe.avocado_toast.flavor': {'en': 'Avocado — healthy fats and creaminess.\nEgg — protein.\nBread — energy.\nTomato — freshness.', 'ru': 'Авокадо — полезные жиры и кремовость.\nЯйцо — белок.\nХлеб — энергия.\nПомидор — свежесть.', 'uk': 'Авокадо — корисні жири і кремовість.\nЯйце — білок.\nХліб — енергія.\nПомідор — свіжість.'},
  'recipe.oat_berry_bowl.pot': {'en': 'Bring milk to a gentle simmer.\nAdd oats, cook on low 5-7 min, stirring.\nOff the heat, top with berries and a little honey.', 'ru': 'Доведите молоко до лёгкого кипения.\nВсыпьте овсянку, варите на слабом огне 5–7 мин, помешивая.\nВне огня добавьте ягоды и немного мёда.', 'uk': 'Доведіть молоко до легкого кипіння.\nВсипте вівсянку, варіть на слабкому вогні 5–7 хв, помішуючи.\nПоза вогнем додайте ягоди й трохи меду.'},
  'recipe.oat_berry_bowl.flavor': {'en': 'Oats — slow carbs and fibre.\nMilk — protein and creaminess.\nBerries — antioxidants.\nHoney — a touch of sweetness.', 'ru': 'Овсянка — медленные углеводы и клетчатка.\nМолоко — белок и кремовость.\nЯгоды — антиоксиданты.\nМёд — немного сладости.', 'uk': 'Вівсянка — повільні вуглеводи і клітковина.\nМолоко — білок і кремовість.\nЯгоди — антиоксиданти.\nМед — трохи солодкості.'},
  'recipe.pepper_scramble.pan': {'en': 'Dice pepper and onion; soften on medium 4 min.\nPour in beaten eggs, stir gently 2-3 min.\nOff the heat, fold in cheese.', 'ru': 'Нарежьте перец и лук; обжарьте на среднем огне 4 мин.\nВлейте взбитые яйца, аккуратно помешивайте 2–3 мин.\nВне огня вмешайте сыр.', 'uk': 'Наріжте перець і цибулю; обсмажте на середньому вогні 4 хв.\nВлийте збиті яйця, обережно помішуйте 2–3 хв.\nПоза вогнем вмішайте сир.'},
  'recipe.pepper_scramble.flavor': {'en': 'Eggs — protein.\nBell pepper — sweetness and vitamin C.\nCheese — richness.\nOnion — aroma.', 'ru': 'Яйца — белок.\nПерец — сладость и витамин C.\nСыр — сытость.\nЛук — аромат.', 'uk': 'Яйця — білок.\nПерець — солодкість і вітамін C.\nСир — ситість.\nЦибуля — аромат.'},
  'recipe.pork_buckwheat.pot': {'en': 'Cook buckwheat 1:2 in water 15 min covered.\nSauté onion and carrot 5 min, add diced pork, brown 10 min.\nCombine with the buckwheat, warm 3 min.', 'ru': 'Сварите гречку 1:2 в воде 15 мин под крышкой.\nОбжарьте лук и морковь 5 мин, добавьте свинину кубиками, обжарьте 10 мин.\nСоедините с гречкой, прогрейте 3 мин.', 'uk': 'Зваріть гречку 1:2 у воді 15 хв під кришкою.\nОбсмажте цибулю й моркву 5 хв, додайте свинину кубиками, обсмажте 10 хв.\nЗ’єднайте з гречкою, прогрійте 3 хв.'},
  'recipe.pork_buckwheat.flavor': {'en': 'Pork — protein and rich flavour.\nBuckwheat — slow carbs.\nCarrot and onion — the base.', 'ru': 'Свинина — белок и насыщенный вкус.\nГречка — медленные углеводы.\nМорковь и лук — база.', 'uk': 'Свинина — білок і насичений смак.\nГречка — повільні вуглеводи.\nМорква й цибуля — база.'},
  'recipe.couscous_chicken.pan': {'en': 'Pour boiling water over couscous 1:1, cover 5 min, fluff.\nPan-fry diced chicken 8 min, add pepper and tomato 4 min.\nFold in the couscous.', 'ru': 'Залейте кускус кипятком 1:1, накройте на 5 мин, взрыхлите.\nОбжарьте курицу кубиками 8 мин, добавьте перец и помидор на 4 мин.\nВмешайте кускус.', 'uk': 'Залийте кускус окропом 1:1, накрийте на 5 хв, розпушіть.\nОбсмажте курку кубиками 8 хв, додайте перець і помідор на 4 хв.\nВмішайте кускус.'},
  'recipe.couscous_chicken.flavor': {'en': 'Chicken — lean protein.\nCouscous — quick carbs.\nPepper and tomato — colour and vitamins.', 'ru': 'Курица — постный белок.\nКускус — быстрые углеводы.\nПерец и помидор — цвет и витамины.', 'uk': 'Курка — пісний білок.\nКускус — швидкі вуглеводи.\nПерець і помідор — колір і вітаміни.'},
  'recipe.bean_soup.pot': {'en': 'Sauté onion and carrot 5 min.\nAdd chopped tomato, cook 3 min.\nAdd beans and water, simmer 15 min; season.', 'ru': 'Обжарьте лук и морковь 5 мин.\nДобавьте нарезанный помидор, готовьте 3 мин.\nДобавьте фасоль и воду, тушите 15 мин; посолите.', 'uk': 'Обсмажте цибулю й моркву 5 хв.\nДодайте нарізаний помідор, готуйте 3 хв.\nДодайте квасолю й воду, тушкуйте 15 хв; посоліть.'},
  'recipe.bean_soup.flavor': {'en': 'Beans — plant protein and fibre.\nTomato — a savoury base.\nCarrot and onion — aroma.', 'ru': 'Фасоль — растительный белок и клетчатка.\nПомидор — насыщенная база.\nМорковь и лук — аромат.', 'uk': 'Квасоля — рослинний білок і клітковина.\nПомідор — насичена база.\nМорква й цибуля — аромат.'},
  'recipe.fish_couscous.pan': {'en': 'Prepare couscous 1:1 with boiling water, cover 5 min.\nPan-fry the fish 3-4 min per side; sauté zucchini and tomato 4 min.\nServe the fish over couscous with the vegetables.', 'ru': 'Приготовьте кускус 1:1 кипятком, накройте на 5 мин.\nОбжарьте рыбу 3–4 мин с каждой стороны; обжарьте кабачок и помидор 4 мин.\nПодайте рыбу на кускусе с овощами.', 'uk': 'Приготуйте кускус 1:1 окропом, накрийте на 5 хв.\nОбсмажте рибу 3–4 хв з кожного боку; обсмажте кабачок і помідор 4 хв.\nПодайте рибу на кускусі з овочами.'},
  'recipe.fish_couscous.flavor': {'en': 'Fish — protein and omega-3.\nCouscous — light carbs.\nZucchini and tomato — freshness.', 'ru': 'Рыба — белок и омега-3.\nКускус — лёгкие углеводы.\nКабачок и помидор — свежесть.', 'uk': 'Риба — білок і омега-3.\nКускус — легкі вуглеводи.\nКабачок і помідор — свіжість.'},
  'recipe.pork_veg.pan': {'en': 'Sear diced pork on high 6 min to brown.\nAdd zucchini, pepper and onion, cook 8 min.\nSeason and cover 2 min to finish.', 'ru': 'Обжарьте свинину кубиками на сильном огне 6 мин до корочки.\nДобавьте кабачок, перец и лук, готовьте 8 мин.\nПосолите и накройте на 2 мин.', 'uk': 'Обсмажте свинину кубиками на сильному вогні 6 хв до скоринки.\nДодайте кабачок, перець і цибулю, готуйте 8 хв.\nПосоліть і накрийте на 2 хв.'},
  'recipe.pork_veg.flavor': {'en': 'Pork — protein and flavour.\nZucchini and pepper — low-carb vegetables.\nOnion — aroma.', 'ru': 'Свинина — белок и вкус.\nКабачок и перец — низкоуглеводные овощи.\nЛук — аромат.', 'uk': 'Свинина — білок і смак.\nКабачок і перець — низьковуглеводні овочі.\nЦибуля — аромат.'},
  'recipe.chicken_beans.pot': {'en': 'Brown diced chicken 8 min.\nAdd onion and chopped tomato, cook 4 min.\nAdd beans and a little water, simmer 10 min; season.', 'ru': 'Обжарьте курицу кубиками 8 мин.\nДобавьте лук и нарезанный помидор, готовьте 4 мин.\nДобавьте фасоль и немного воды, тушите 10 мин; посолите.', 'uk': 'Обсмажте курку кубиками 8 хв.\nДодайте цибулю й нарізаний помідор, готуйте 4 хв.\nДодайте квасолю й трохи води, тушкуйте 10 хв; посоліть.'},
  'recipe.chicken_beans.flavor': {'en': 'Chicken — lean protein.\nBeans — extra protein and fibre.\nTomato — a savoury sauce.', 'ru': 'Курица — постный белок.\nФасоль — дополнительный белок и клетчатка.\nПомидор — насыщенный соус.', 'uk': 'Курка — пісний білок.\nКвасоля — додатковий білок і клітковина.\nПомідор — насичений соус.'},
  'recipe.avocado_chicken_salad.pan': {'en': 'Sear diced chicken 8 min until cooked through.\nDice avocado, cucumber and tomato into a bowl.\nAdd the warm chicken, oil and salt; toss gently.', 'ru': 'Обжарьте курицу кубиками 8 мин до готовности.\nНарежьте авокадо, огурец и помидор в миску.\nДобавьте тёплую курицу, масло и соль; аккуратно перемешайте.', 'uk': 'Обсмажте курку кубиками 8 хв до готовності.\nНаріжте авокадо, огірок і помідор у миску.\nДодайте теплу курку, олію й сіль; обережно перемішайте.'},
  'recipe.avocado_chicken_salad.flavor': {'en': 'Chicken — protein.\nAvocado — healthy fats and creaminess.\nCucumber and tomato — freshness.', 'ru': 'Курица — белок.\nАвокадо — полезные жиры и кремовость.\nОгурец и помидор — свежесть.', 'uk': 'Курка — білок.\nАвокадо — корисні жири і кремовість.\nОгірок і помідор — свіжість.'},
  'recipe.corn_tuna_salad.assembly': {'en': 'Drain the tuna and corn.\nDice cucumber and tomato, combine everything.\nDress with oil and salt; toss.', 'ru': 'Слейте жидкость с тунца и кукурузы.\nНарежьте огурец и помидор, соедините всё.\nЗаправьте маслом и солью; перемешайте.', 'uk': 'Злийте рідину з тунця й кукурудзи.\nНаріжте огірок і помідор, з’єднайте все.\nЗаправте олією й сіллю; перемішайте.'},
  'recipe.corn_tuna_salad.flavor': {'en': 'Tuna — lean protein.\nCorn — sweetness and carbs.\nCucumber and tomato — freshness.', 'ru': 'Тунец — постный белок.\nКукуруза — сладость и углеводы.\nОгурец и помидор — свежесть.', 'uk': 'Тунець — пісний білок.\nКукурудза — солодкість і вуглеводи.\nОгірок і помідор — свіжість.'},
  'recipe.avocado_egg.assembly': {'en': 'Boil the egg 7-9 min, cool and peel.\nHalve the avocado, remove the stone.\nSlice both, season with salt.', 'ru': 'Отварите яйцо 7–9 мин, остудите и очистите.\nРазрежьте авокадо, удалите косточку.\nНарежьте оба, посолите.', 'uk': 'Відваріть яйце 7–9 хв, остудіть і очистіть.\nРозріжте авокадо, видаліть кісточку.\nНаріжте обидва, посоліть.'},
  'recipe.avocado_egg.flavor': {'en': 'Avocado — healthy fats and fibre.\nEgg — protein; together, low-carb and filling.', 'ru': 'Авокадо — полезные жиры и клетчатка.\nЯйцо — белок; вместе — сытно и мало углеводов.', 'uk': 'Авокадо — корисні жири і клітковина.\nЯйце — білок; разом — ситно і мало вуглеводів.'},
  'recipe.cottage_honey.assembly': {'en': 'Put the cottage cheese in a bowl.\nDrizzle honey over the top; stir if you like.', 'ru': 'Выложите творог в миску.\nПолейте мёдом сверху; при желании перемешайте.', 'uk': 'Викладіть сир у миску.\nПолийте медом зверху; за бажанням перемішайте.'},
  'recipe.cottage_honey.flavor': {'en': 'Cottage cheese — protein.\nHoney — natural sweetness and quick energy.', 'ru': 'Творог — белок.\nМёд — натуральная сладость и быстрая энергия.', 'uk': 'Сир — білок.\nМед — натуральна солодкість і швидка енергія.'},
  'recipe.yogurt_oats.assembly': {'en': 'Stir the oats into the yogurt.\nRest 5-10 min so the oats soften (or overnight).', 'ru': 'Вмешайте овсянку в йогурт.\nДайте постоять 5–10 мин, чтобы овсянка размякла (или на ночь).', 'uk': 'Вмішайте вівсянку в йогурт.\nДайте постояти 5–10 хв, щоб вівсянка розм’якла (або на ніч).'},
  'recipe.yogurt_oats.flavor': {'en': 'Yogurt — protein and probiotics.\nOats — fibre and staying power.', 'ru': 'Йогурт — белок и пробиотики.\nОвсянка — клетчатка и сытость.', 'uk': 'Йогурт — білок і пробіотики.\nВівсянка — клітковина і ситість.'},
  'recipe.pepper_cheese.assembly': {'en': 'Cut the bell pepper into strips.\nCut the cheese into sticks.\nServe together — crunchy and low-carb.', 'ru': 'Нарежьте перец полосками.\nНарежьте сыр брусочками.\nПодавайте вместе — хрустящий низкоуглеводный перекус.', 'uk': 'Наріжте перець смужками.\nНаріжте сир брусочками.\nПодавайте разом — хрусткий низьковуглеводний перекус.'},
  'recipe.pepper_cheese.flavor': {'en': 'Bell pepper — crunch, vitamin C, low carb.\nCheese — protein and fats.', 'ru': 'Перец — хруст, витамин C, мало углеводов.\nСыр — белок и жиры.', 'uk': 'Перець — хрускіт, вітамін C, мало вуглеводів.\nСир — білок і жири.'},
  'recipe.peanut_banana_toast.assembly': {'en': 'Toast the bread.\nSpread peanut butter over it.\nTop with banana slices.', 'ru': 'Подрумяньте хлеб.\nНамажьте арахисовой пастой.\nВыложите сверху ломтики банана.', 'uk': 'Підрум’яньте хліб.\nНамастіть арахісовою пастою.\nВикладіть зверху скибочки банана.'},
  'recipe.peanut_banana_toast.flavor': {'en': 'Peanut butter — protein and healthy fats.\nBanana — natural sweetness and potassium.\nBread — energy.', 'ru': 'Арахисовая паста — белок и полезные жиры.\nБанан — натуральная сладость и калий.\nХлеб — энергия.', 'uk': 'Арахісова паста — білок і корисні жири.\nБанан — натуральна солодкість і калій.\nХліб — енергія.'},
  'recipe.quinoa_porridge.pot': {'en': 'Rinse quinoa well.\nSimmer in the milk on low 15 min, stirring.\nOff the heat, add berries and honey.', 'ru': 'Хорошо промойте киноа.\nВарите в молоке на слабом огне 15 мин, помешивая.\nВне огня добавьте ягоды и мёд.', 'uk': 'Добре промийте кіноа.\nВаріть у молоці на слабкому вогні 15 хв, помішуючи.\nПоза вогнем додайте ягоди й мед.'},
  'recipe.quinoa_porridge.flavor': {'en': 'Quinoa — complete plant protein and fibre.\nMilk — creaminess.\nBerries and honey — sweetness.', 'ru': 'Киноа — полноценный растительный белок и клетчатка.\nМолоко — кремовость.\nЯгоды и мёд — сладость.', 'uk': 'Кіноа — повноцінний рослинний білок і клітковина.\nМолоко — кремовість.\nЯгоди й мед — солодкість.'},
  'recipe.feta_veggie_eggs.pan': {'en': 'Wilt the spinach 1-2 min, add chopped tomato 1 min.\nPour in beaten eggs, cook 3 min.\nCrumble feta on top, cover 1 min.', 'ru': 'Припустите шпинат 1–2 мин, добавьте помидор на 1 мин.\nВлейте взбитые яйца, готовьте 3 мин.\nРаскрошите фету сверху, накройте на 1 мин.', 'uk': 'Припустіть шпинат 1–2 хв, додайте помідор на 1 хв.\nВлийте збиті яйця, готуйте 3 хв.\nРозкришіть фету зверху, накрийте на 1 хв.'},
  'recipe.feta_veggie_eggs.flavor': {'en': 'Eggs — protein.\nFeta — salty, tangy richness.\nSpinach — iron.\nTomato — freshness.', 'ru': 'Яйца — белок.\nФета — солёная сытость.\nШпинат — железо.\nПомидор — свежесть.', 'uk': 'Яйця — білок.\nФета — солона ситість.\nШпинат — залізо.\nПомідор — свіжість.'},
  'recipe.cottage_banana.assembly': {'en': 'Mash the banana into the cottage cheese.\nStir in the oats and honey.\nBest after 5 min so the oats soften.', 'ru': 'Разомните банан в твороге.\nВмешайте овсянку и мёд.\nЛучше через 5 мин, чтобы овсянка размякла.', 'uk': 'Розімніть банан у сирі.\nВмішайте вівсянку й мед.\nКраще за 5 хв, щоб вівсянка розм’якла.'},
  'recipe.cottage_banana.flavor': {'en': 'Cottage cheese — protein.\nBanana and honey — natural sweetness.\nOats — fibre.', 'ru': 'Творог — белок.\nБанан и мёд — натуральная сладость.\nОвсянка — клетчатка.', 'uk': 'Сир — білок.\nБанан і мед — натуральна солодкість.\nВівсянка — клітковина.'},
  'recipe.mushroom_toast.pan': {'en': 'Sauté sliced mushrooms 5 min until dry.\nToast the bread; fry the egg to your liking.\nTop toast with mushrooms, cheese and the egg.', 'ru': 'Обжарьте нарезанные грибы 5 мин до сухости.\nПодрумяньте хлеб; пожарьте яйцо по вкусу.\nВыложите на тост грибы, сыр и яйцо.', 'uk': 'Обсмажте нарізані гриби 5 хв до сухості.\nПідрум’яньте хліб; посмажте яйце до смаку.\nВикладіть на тост гриби, сир і яйце.'},
  'recipe.mushroom_toast.flavor': {'en': 'Mushrooms — savoury umami.\nCheese — melt and protein.\nEgg — protein.\nBread — the base.', 'ru': 'Грибы — умами.\nСыр — тягучесть и белок.\nЯйцо — белок.\nХлеб — основа.', 'uk': 'Гриби — умамі.\nСир — тягучість і білок.\nЯйце — білок.\nХліб — основа.'},
  'recipe.chicken_quinoa.pan': {'en': 'Rinse and boil quinoa 15 min, drain.\nPan-fry diced chicken 8 min; steam broccoli and carrot 5 min.\nCombine everything, season.', 'ru': 'Промойте и отварите киноа 15 мин, слейте.\nОбжарьте курицу кубиками 8 мин; припустите брокколи и морковь 5 мин.\nСоедините всё, посолите.', 'uk': 'Промийте й відваріть кіноа 15 хв, злийте.\nОбсмажте курку кубиками 8 хв; припустіть броколі й моркву 5 хв.\nЗ’єднайте все, посоліть.'},
  'recipe.chicken_quinoa.flavor': {'en': 'Chicken — lean protein.\nQuinoa — complete protein and fibre.\nBroccoli and carrot — vitamins.', 'ru': 'Курица — постный белок.\nКиноа — полноценный белок и клетчатка.\nБрокколи и морковь — витамины.', 'uk': 'Курка — пісний білок.\nКіноа — повноцінний білок і клітковина.\nБроколі й морква — вітаміни.'},
  'recipe.beef_rice_veg.pot': {'en': 'Boil the rice 12-15 min.\nBrown diced beef 6 min, add onion and green beans, cook 8 min.\nCombine with the rice, season.', 'ru': 'Отварите рис 12–15 мин.\nОбжарьте говядину кубиками 6 мин, добавьте лук и фасоль, готовьте 8 мин.\nСоедините с рисом, посолите.', 'uk': 'Відваріть рис 12–15 хв.\nОбсмажте яловичину кубиками 6 хв, додайте цибулю й квасолю, готуйте 8 хв.\nЗ’єднайте з рисом, посоліть.'},
  'recipe.beef_rice_veg.flavor': {'en': 'Beef — protein and iron.\nRice — energy.\nGreen beans — fibre and crunch.', 'ru': 'Говядина — белок и железо.\nРис — энергия.\nСтручковая фасоль — клетчатка и хруст.', 'uk': 'Яловичина — білок і залізо.\nРис — енергія.\nСтручкова квасоля — клітковина і хрускіт.'},
  'recipe.salmon_potato.oven': {'en': 'Heat the oven to 200 °C.\nCut potatoes into wedges, toss with oil; bake 15 min.\nAdd salmon and green beans, bake 15 min more.', 'ru': 'Разогрейте духовку до 200 °C.\nНарежьте картофель дольками, перемешайте с маслом; запекайте 15 мин.\nДобавьте лосось и фасоль, запекайте ещё 15 мин.', 'uk': 'Розігрійте духовку до 200 °C.\nНаріжте картоплю часточками, перемішайте з олією; запікайте 15 хв.\nДодайте лосось і квасолю, запікайте ще 15 хв.'},
  'recipe.salmon_potato.flavor': {'en': 'Salmon — protein and omega-3.\nPotatoes — heartiness.\nGreen beans — fibre.', 'ru': 'Лосось — белок и омега-3.\nКартофель — сытность.\nСтручковая фасоль — клетчатка.', 'uk': 'Лосось — білок і омега-3.\nКартопля — ситність.\nСтручкова квасоля — клітковина.'},
  'recipe.turkey_pasta.pan': {'en': 'Boil the pasta 8-10 min, drain.\nFry diced turkey 8 min, add onion and tomato 4 min.\nToss in the pasta with a splash of water.', 'ru': 'Отварите пасту 8–10 мин, слейте.\nОбжарьте индейку кубиками 8 мин, добавьте лук и помидор на 4 мин.\nВмешайте пасту с ложкой воды.', 'uk': 'Відваріть пасту 8–10 хв, злийте.\nОбсмажте індичку кубиками 8 хв, додайте цибулю й помідор на 4 хв.\nВмішайте пасту з ложкою води.'},
  'recipe.turkey_pasta.flavor': {'en': 'Turkey — very lean protein.\nPasta — the base.\nTomato and onion — a light sauce.', 'ru': 'Индейка — очень постный белок.\nПаста — основа.\nПомидор и лук — лёгкий соус.', 'uk': 'Індичка — дуже пісний білок.\nПаста — основа.\nПомідор і цибуля — легкий соус.'},
  'recipe.veggie_quinoa_bowl.pot': {'en': 'Rinse and boil quinoa 15 min, drain and cool a little.\nDrain the chickpeas; dice tomato and cucumber.\nCombine everything, dress with oil and salt.', 'ru': 'Промойте и отварите киноа 15 мин, слейте и слегка остудите.\nСлейте нут; нарежьте помидор и огурец.\nСоедините всё, заправьте маслом и солью.', 'uk': 'Промийте й відваріть кіноа 15 хв, злийте й трохи остудіть.\nЗлийте нут; наріжте помідор і огірок.\nЗ’єднайте все, заправте олією й сіллю.'},
  'recipe.veggie_quinoa_bowl.flavor': {'en': 'Quinoa and chickpeas — plant protein and fibre.\nTomato and cucumber — freshness.', 'ru': 'Киноа и нут — растительный белок и клетчатка.\nПомидор и огурец — свежесть.', 'uk': 'Кіноа й нут — рослинний білок і клітковина.\nПомідор і огірок — свіжість.'},
  'recipe.baked_fish_veg.oven': {'en': 'Heat the oven to 200 °C.\nCut zucchini, pepper and tomato, toss with oil and salt.\nAdd the fish, bake together 20-25 min.', 'ru': 'Разогрейте духовку до 200 °C.\nНарежьте кабачок, перец и помидор, перемешайте с маслом и солью.\nДобавьте рыбу, запекайте вместе 20–25 мин.', 'uk': 'Розігрійте духовку до 200 °C.\nНаріжте кабачок, перець і помідор, перемішайте з олією й сіллю.\nДодайте рибу, запікайте разом 20–25 хв.'},
  'recipe.baked_fish_veg.flavor': {'en': 'Fish — protein and omega-3.\nZucchini and pepper — low-carb vegetables.\nTomato — juiciness.', 'ru': 'Рыба — белок и омега-3.\nКабачок и перец — низкоуглеводные овощи.\nПомидор — сочность.', 'uk': 'Риба — білок і омега-3.\nКабачок і перець — низьковуглеводні овочі.\nПомідор — соковитість.'},
  'recipe.chicken_sweet_potato.oven': {'en': 'Heat the oven to 200 °C.\nCube the sweet potato, toss with oil; bake 15 min.\nAdd the seasoned chicken and broccoli, bake 20 min more.', 'ru': 'Разогрейте духовку до 200 °C.\nНарежьте батат кубиками, перемешайте с маслом; запекайте 15 мин.\nДобавьте приправленную курицу и брокколи, запекайте ещё 20 мин.', 'uk': 'Розігрійте духовку до 200 °C.\nНаріжте батат кубиками, перемішайте з олією; запікайте 15 хв.\nДодайте приправлену курку й броколі, запікайте ще 20 хв.'},
  'recipe.chicken_sweet_potato.flavor': {'en': 'Chicken — protein.\nSweet potato — slow carbs and beta-carotene.\nBroccoli — fibre and vitamin C.', 'ru': 'Курица — белок.\nБатат — медленные углеводы и бета-каротин.\nБрокколи — клетчатка и витамин C.', 'uk': 'Курка — білок.\nБатат — повільні вуглеводи й бета-каротин.\nБроколі — клітковина й вітамін C.'},
  'recipe.pork_grill.grill': {'en': 'Marinate pork and thick-cut vegetables 20 min.\nGrill over medium: pork 7 min per side, vegetables 8-10 min.\nRest the pork 5 min before slicing.', 'ru': 'Замаринуйте свинину и крупно нарезанные овощи 20 мин.\nГотовьте на среднем жаре: свинина 7 мин с каждой стороны, овощи 8–10 мин.\nДайте свинине отдохнуть 5 мин перед нарезкой.', 'uk': 'Замаринуйте свинину й велико нарізані овочі 20 хв.\nГотуйте на середньому жарі: свинина 7 хв з кожного боку, овочі 8–10 хв.\nДайте свинині відпочити 5 хв перед нарізанням.'},
  'recipe.pork_grill.flavor': {'en': 'Pork — protein and rich flavour.\nZucchini and onion — smoky vegetables.\nTomato — juiciness.', 'ru': 'Свинина — белок и насыщенный вкус.\nКабачок и лук — овощи с дымком.\nПомидор — сочность.', 'uk': 'Свинина — білок і насичений смак.\nКабачок і цибуля — овочі з димком.\nПомідор — соковитість.'},
  'recipe.greek_salad.assembly': {'en': 'Cut cucumber and tomato into chunks.\nAdd thin onion and cubed feta.\nDrizzle with oil, season; toss gently.', 'ru': 'Нарежьте огурец и помидор крупно.\nДобавьте тонкий лук и кубики феты.\nСбрызните маслом, посолите; аккуратно перемешайте.', 'uk': 'Наріжте огірок і помідор великими шматками.\nДодайте тонку цибулю й кубики фети.\nЗбризніть олією, посоліть; обережно перемішайте.'},
  'recipe.greek_salad.flavor': {'en': 'Feta — salty, tangy protein.\nCucumber and tomato — freshness.\nOnion and oil — Mediterranean flavour.', 'ru': 'Фета — солёный белок с кислинкой.\nОгурец и помидор — свежесть.\nЛук и масло — средиземноморский вкус.', 'uk': 'Фета — солоний білок з кислинкою.\nОгірок і помідор — свіжість.\nЦибуля й олія — середземноморський смак.'},
  'recipe.turkey_veg_stew.pot': {'en': 'Sauté onion-free base: brown diced turkey 6 min.\nAdd carrot, potato and green beans with a little water.\nStew covered 20 min; season.', 'ru': 'Обжарьте индейку кубиками 6 мин.\nДобавьте морковь, картофель и фасоль с небольшим количеством воды.\nТушите под крышкой 20 мин; посолите.', 'uk': 'Обсмажте індичку кубиками 6 хв.\nДодайте моркву, картоплю й квасолю з невеликою кількістю води.\nТушкуйте під кришкою 20 хв; посоліть.'},
  'recipe.turkey_veg_stew.flavor': {'en': 'Turkey — very lean protein.\nPotato — heartiness.\nCarrot and green beans — fibre and sweetness.', 'ru': 'Индейка — очень постный белок.\nКартофель — сытность.\nМорковь и фасоль — клетчатка и сладость.', 'uk': 'Індичка — дуже пісний білок.\nКартопля — ситність.\nМорква й квасоля — клітковина й солодкість.'},
  'recipe.peanut_apple.assembly': {'en': 'Slice the apple into wedges.\nServe with peanut butter to dip.', 'ru': 'Нарежьте яблоко дольками.\nПодавайте с арахисовой пастой для макания.', 'uk': 'Наріжте яблуко часточками.\nПодавайте з арахісовою пастою для вмочування.'},
  'recipe.peanut_apple.flavor': {'en': 'Apple — fibre and freshness.\nPeanut butter — protein and healthy fats.', 'ru': 'Яблоко — клетчатка и свежесть.\nАрахисовая паста — белок и полезные жиры.', 'uk': 'Яблуко — клітковина і свіжість.\nАрахісова паста — білок і корисні жири.'},
  'recipe.feta_cucumber.assembly': {'en': 'Slice the cucumber.\nCube the feta and combine; a pinch of herbs is nice.', 'ru': 'Нарежьте огурец.\nНарежьте фету кубиками и соедините; хорошо со щепоткой зелени.', 'uk': 'Наріжте огірок.\nНаріжте фету кубиками й з’єднайте; добре з дрібкою зелені.'},
  'recipe.feta_cucumber.flavor': {'en': 'Feta — salty protein.\nCucumber — fresh, crunchy and low-carb.', 'ru': 'Фета — солёный белок.\nОгурец — свежий, хрустящий, мало углеводов.', 'uk': 'Фета — солоний білок.\nОгірок — свіжий, хрусткий, мало вуглеводів.'},
  'recipe.banana_milk.assembly': {'en': 'Put milk and banana in a blender.\nBlend 20-30 sec until smooth.', 'ru': 'Положите молоко и банан в блендер.\nВзбейте 20–30 сек до однородности.', 'uk': 'Покладіть молоко й банан у блендер.\nЗбийте 20–30 сек до однорідності.'},
  'recipe.banana_milk.flavor': {'en': 'Milk — protein and calcium.\nBanana — natural sweetness and potassium.', 'ru': 'Молоко — белок и кальций.\nБанан — натуральная сладость и калий.', 'uk': 'Молоко — білок і кальцій.\nБанан — натуральна солодкість і калій.'},
  'recipe.cottage_nuts.assembly': {'en': 'Put the cottage cheese in a bowl.\nScatter chopped walnuts on top.', 'ru': 'Выложите творог в миску.\nПосыпьте рублеными орехами.', 'uk': 'Викладіть сир у миску.\nПосипте рубленими горіхами.'},
  'recipe.cottage_nuts.flavor': {'en': 'Cottage cheese — lean protein.\nWalnuts — healthy fats and crunch.', 'ru': 'Творог — постный белок.\nОрехи — полезные жиры и хруст.', 'uk': 'Сир — пісний білок.\nГоріхи — корисні жири і хрускіт.'},
  'recipe.shakshuka.pan': {'en': 'Soften onion and pepper 5 min.\nAdd chopped tomato, simmer 8-10 min into a thick sauce.\nMake wells, crack in the eggs, cover and cook 5-6 min.', 'ru': 'Обжарьте лук и перец 5 мин.\nДобавьте нарезанный помидор, тушите 8–10 мин до густого соуса.\nСделайте углубления, вбейте яйца, накройте и готовьте 5–6 мин.', 'uk': 'Обсмажте цибулю й перець 5 хв.\nДодайте нарізаний помідор, тушкуйте 8–10 хв до густого соусу.\nЗробіть заглиблення, вбийте яйця, накрийте й готуйте 5–6 хв.'},
  'recipe.shakshuka.flavor': {'en': 'Eggs — protein poached in the sauce.\nTomato and pepper — a rich, sweet base.\nOnion — depth of flavour.', 'ru': 'Яйца — белок, припущенный в соусе.\nПомидор и перец — насыщенная сладкая база.\nЛук — глубина вкуса.', 'uk': 'Яйця — білок, припущений у соусі.\nПомідор і перець — насичена солодка база.\nЦибуля — глибина смаку.'},
  'recipe.granola_yogurt.assembly': {'en': 'Spoon yogurt into a bowl.\nToast the oats in a dry pan 3 min for crunch (optional).\nAdd oats, berries and a drizzle of honey.', 'ru': 'Выложите йогурт в миску.\nПодсушите овсянку на сухой сковороде 3 мин для хруста (по желанию).\nДобавьте овсянку, ягоды и немного мёда.', 'uk': 'Викладіть йогурт у миску.\nПідсушіть вівсянку на сухій сковороді 3 хв для хрускоту (за бажанням).\nДодайте вівсянку, ягоди й трохи меду.'},
  'recipe.granola_yogurt.flavor': {'en': 'Yogurt — protein and probiotics.\nOats — fibre and crunch.\nBerries — antioxidants.\nHoney — sweetness.', 'ru': 'Йогурт — белок и пробиотики.\nОвсянка — клетчатка и хруст.\nЯгоды — антиоксиданты.\nМёд — сладость.', 'uk': 'Йогурт — білок і пробіотики.\nВівсянка — клітковина і хрускіт.\nЯгоди — антиоксиданти.\nМед — солодкість.'},
  'recipe.japanese_rice_egg.pot': {'en': 'Cook the rice until soft and sticky.\nBeat one egg raw or soft-boil both.\nStir the egg through the hot rice; season with a little soy.', 'ru': 'Отварите рис до мягкости и клейкости.\nВзбейте одно яйцо сырым или отварите всмятку.\nВмешайте яйцо в горячий рис; приправьте соевым соусом.', 'uk': 'Відваріть рис до м’якості й клейкості.\nЗбийте одне яйце сирим або відваріть некруто.\nВмішайте яйце в гарячий рис; приправте соєвим соусом.'},
  'recipe.japanese_rice_egg.flavor': {'en': 'Rice — comforting base.\nEgg — silky protein that coats the rice.', 'ru': 'Рис — уютная основа.\nЯйцо — шелковистый белок, обволакивающий рис.', 'uk': 'Рис — затишна основа.\nЯйце — шовковистий білок, що обволікає рис.'},
  'recipe.italian_pasta.pan': {'en': 'Boil the pasta 8-10 min, drain.\nSoften onion 3 min, add chopped tomato, simmer 10 min.\nToss the pasta through the sauce; finish with cheese.', 'ru': 'Отварите пасту 8–10 мин, слейте.\nОбжарьте лук 3 мин, добавьте помидор, тушите 10 мин.\nВмешайте пасту в соус; завершите сыром.', 'uk': 'Відваріть пасту 8–10 хв, злийте.\nОбсмажте цибулю 3 хв, додайте помідор, тушкуйте 10 хв.\nВмішайте пасту в соус; завершіть сиром.'},
  'recipe.italian_pasta.flavor': {'en': 'Pasta — the base.\nTomato — a bright, slow-cooked sauce.\nCheese — savoury depth.\nOnion — aroma.', 'ru': 'Паста — основа.\nПомидор — яркий томлёный соус.\nСыр — солёная глубина.\nЛук — аромат.', 'uk': 'Паста — основа.\nПомідор — яскравий томлений соус.\nСир — солона глибина.\nЦибуля — аромат.'},
  'recipe.georgian_chicken.pan': {'en': 'Brown diced chicken 8 min.\nAdd onion and chopped tomato, simmer 12 min.\nStir in crushed walnuts and herbs; rest 5 min.', 'ru': 'Обжарьте курицу кубиками 8 мин.\nДобавьте лук и нарезанный помидор, тушите 12 мин.\nВмешайте толчёные орехи и зелень; дайте настояться 5 мин.', 'uk': 'Обсмажте курку кубиками 8 хв.\nДодайте цибулю й нарізаний помідор, тушкуйте 12 хв.\nВмішайте товчені горіхи й зелень; дайте настоятися 5 хв.'},
  'recipe.georgian_chicken.flavor': {'en': 'Chicken — protein braised in tomato.\nWalnuts — the signature rich, nutty note.\nOnion and tomato — the sauce.', 'ru': 'Курица — белок, томлённый в помидоре.\nОрехи — фирменная насыщенная ореховая нота.\nЛук и помидор — соус.', 'uk': 'Курка — білок, томлений у помідорі.\nГоріхи — фірмова насичена горіхова нота.\nЦибуля й помідор — соус.'},
  'recipe.mexican_bowl.pot': {'en': 'Boil the rice 12-15 min.\nWarm the beans and corn with a little water 5 min.\nBuild a bowl: rice, beans, corn and fresh diced tomato.', 'ru': 'Отварите рис 12–15 мин.\nПрогрейте фасоль и кукурузу с ложкой воды 5 мин.\nСоберите боул: рис, фасоль, кукуруза и свежий помидор.', 'uk': 'Відваріть рис 12–15 хв.\nПрогрійте квасолю й кукурудзу з ложкою води 5 хв.\nЗберіть боул: рис, квасоля, кукурудза й свіжий помідор.'},
  'recipe.mexican_bowl.flavor': {'en': 'Beans — plant protein and fibre.\nRice — the base.\nCorn — sweetness (in season late summer).\nTomato — freshness.', 'ru': 'Фасоль — растительный белок и клетчатка.\nРис — основа.\nКукуруза — сладость (сезон — конец лета).\nПомидор — свежесть.', 'uk': 'Квасоля — рослинний білок і клітковина.\nРис — основа.\nКукурудза — солодкість (сезон — кінець літа).\nПомідор — свіжість.'},
  'recipe.indian_dhal.pot': {'en': 'Rinse the lentils.\nSauté onion and carrot 5 min, add chopped tomato and spices.\nAdd lentils and water, simmer 20-25 min until creamy.', 'ru': 'Промойте чечевицу.\nОбжарьте лук и морковь 5 мин, добавьте помидор и специи.\nДобавьте чечевицу и воду, тушите 20–25 мин до кремовости.', 'uk': 'Промийте сочевицю.\nОбсмажте цибулю й моркву 5 хв, додайте помідор і спеції.\nДодайте сочевицю й воду, тушкуйте 20–25 хв до кремовості.'},
  'recipe.indian_dhal.flavor': {'en': 'Lentils — plant protein, fibre and a creamy body.\nTomato and spices — a warm, aromatic base.', 'ru': 'Чечевица — растительный белок, клетчатка и кремовая текстура.\nПомидор и специи — тёплая ароматная база.', 'uk': 'Сочевиця — рослинний білок, клітковина й кремова текстура.\nПомідор і спеції — тепла ароматна база.'},
  'recipe.pumpkin_soup.pot': {'en': 'Cube pumpkin and carrot, soften onion 5 min.\nAdd pumpkin, carrot and water, simmer 20 min until soft.\nBlend smooth, stir in the milk; warm and season.', 'ru': 'Нарежьте тыкву и морковь, обжарьте лук 5 мин.\nДобавьте тыкву, морковь и воду, варите 20 мин до мягкости.\nПробейте блендером, вмешайте молоко; прогрейте и посолите.', 'uk': 'Наріжте гарбуз і моркву, обсмажте цибулю 5 хв.\nДодайте гарбуз, моркву й воду, варіть 20 хв до м’якості.\nПробийте блендером, вмішайте молоко; прогрійте й посоліть.'},
  'recipe.pumpkin_soup.flavor': {'en': 'Pumpkin — sweet, creamy autumn vegetable (in season).\nCarrot — sweetness.\nMilk — a velvety finish.', 'ru': 'Тыква — сладкий кремовый осенний овощ (в сезоне).\nМорковь — сладость.\nМолоко — бархатистость.', 'uk': 'Гарбуз — солодкий кремовий осінній овоч (у сезоні).\nМорква — солодкість.\nМолоко — оксамитовість.'},
  'recipe.greek_chicken_bowl.pan': {'en': 'Sear diced chicken 8 min until cooked.\nChop cucumber and tomato into a bowl.\nAdd the chicken and crumbled feta; drizzle with oil.', 'ru': 'Обжарьте курицу кубиками 8 мин до готовности.\nНарежьте огурец и помидор в миску.\nДобавьте курицу и раскрошенную фету; сбрызните маслом.', 'uk': 'Обсмажте курку кубиками 8 хв до готовності.\nНаріжте огірок і помідор у миску.\nДодайте курку й розкришену фету; збризніть олією.'},
  'recipe.greek_chicken_bowl.flavor': {'en': 'Chicken — protein.\nFeta — salty, tangy richness.\nCucumber and tomato — Mediterranean freshness.', 'ru': 'Курица — белок.\nФета — солёная сытость с кислинкой.\nОгурец и помидор — средиземноморская свежесть.', 'uk': 'Курка — білок.\nФета — солона ситість з кислинкою.\nОгірок і помідор — середземноморська свіжість.'},
  'recipe.spanish_gazpacho.assembly': {'en': 'Roughly chop tomato, cucumber and pepper.\nSoak the bread briefly, then blend everything smooth with oil.\nChill 30 min; serve cold.', 'ru': 'Крупно нарежьте помидор, огурец и перец.\nЗамочите хлеб ненадолго, взбейте всё с маслом до однородности.\nОхладите 30 мин; подавайте холодным.', 'uk': 'Велико наріжте помідор, огірок і перець.\nЗамочіть хліб ненадовго, збийте все з олією до однорідності.\nОхолодіть 30 хв; подавайте холодним.'},
  'recipe.spanish_gazpacho.flavor': {'en': 'Tomato — the sweet, fresh heart (in season summer).\nCucumber and pepper — freshness.\nBread — body; oil — smoothness.', 'ru': 'Помидор — сладкое свежее сердце (сезон — лето).\nОгурец и перец — свежесть.\nХлеб — плотность; масло — гладкость.', 'uk': 'Помідор — солодке свіже серце (сезон — літо).\nОгірок і перець — свіжість.\nХліб — щільність; олія — гладкість.'},
  'recipe.japanese_salmon_bowl.pan': {'en': 'Cook the rice until sticky.\nSear the salmon 3 min per side, flake into pieces.\nBuild a bowl: rice, salmon and sliced cucumber; add soy if you like.', 'ru': 'Отварите рис до клейкости.\nОбжарьте лосось 3 мин с каждой стороны, разберите на кусочки.\nСоберите боул: рис, лосось и нарезанный огурец; по желанию соевый соус.', 'uk': 'Відваріть рис до клейкості.\nОбсмажте лосось 3 хв з кожного боку, розберіть на шматочки.\nЗберіть боул: рис, лосось і нарізаний огірок; за бажанням соєвий соус.'},
  'recipe.japanese_salmon_bowl.flavor': {'en': 'Salmon — protein and omega-3.\nRice — the base.\nCucumber — cool, fresh crunch.', 'ru': 'Лосось — белок и омега-3.\nРис — основа.\nОгурец — прохладный свежий хруст.', 'uk': 'Лосось — білок і омега-3.\nРис — основа.\nОгірок — прохолодний свіжий хрускіт.'},
  'recipe.watermelon_feta.assembly': {'en': 'Cube the watermelon.\nCrumble or cube the feta over it.\nBest cold; a few mint leaves are lovely.', 'ru': 'Нарежьте арбуз кубиками.\nРаскрошите или нарежьте фету сверху.\nЛучше холодным; хорошо с листиками мяты.', 'uk': 'Наріжте кавун кубиками.\nРозкришіть або наріжте фету зверху.\nКраще холодним; добре з листочками м’яти.'},
  'recipe.watermelon_feta.flavor': {'en': 'Watermelon — sweet, hydrating summer fruit (in season).\nFeta — a salty contrast that makes it pop.', 'ru': 'Арбуз — сладкий сочный летний фрукт (в сезоне).\nФета — солёный контраст, который раскрывает вкус.', 'uk': 'Кавун — солодкий соковитий літній фрукт (у сезоні).\nФета — солоний контраст, що розкриває смак.'},
  'diet.plan.mediterranean.how': {'en': 'Built on vegetables, fruit, whole grains, legumes, fish and olive oil; red meat and sweets stay rare. It is about food quality and eating patterns rather than counting calories.', 'ru': 'Основа — овощи, фрукты, цельные злаки, бобовые, рыба и оливковое масло; красное мясо и сладкое — редко. Дело не в подсчёте калорий, а в качестве продуктов.', 'uk': 'Основа — овочі, фрукти, цільні злаки, бобові, риба та оливкова олія; червоне м’ясо й солодке — рідко. Річ не в підрахунку калорій, а в якості продуктів.'},
  'diet.plan.mediterranean.pro1': {'en': 'Proven benefits for the heart and vessels.', 'ru': 'Доказанная польза для сердца и сосудов.', 'uk': 'Доведена користь для серця й судин.'},
  'diet.plan.mediterranean.pro2': {'en': 'Varied and filling — easy to keep for years.', 'ru': 'Разнообразно и сытно — легко придерживаться годами.', 'uk': 'Різноманітно й ситно — легко дотримуватися роками.'},
  'diet.plan.mediterranean.pro3': {'en': 'Lots of fibre and healthy fats.', 'ru': 'Много клетчатки и полезных жиров.', 'uk': 'Багато клітковини та корисних жирів.'},
  'diet.plan.mediterranean.con1': {'en': 'Fish and olive oil can be pricier.', 'ru': 'Рыба и оливковое масло могут быть дороже.', 'uk': 'Риба та оливкова олія можуть бути дорожчими.'},
  'diet.plan.mediterranean.con2': {'en': 'No strict portions — easy to overeat if unchecked.', 'ru': 'Нет жёстких порций — можно переесть, если не следить.', 'uk': 'Немає жорстких порцій — можна переїсти, якщо не стежити.'},
  'diet.plan.mediterranean.con3': {'en': 'Weight loss is gradual, not fast.', 'ru': 'Снижение веса медленное, не быстрое.', 'uk': 'Зниження ваги повільне, не швидке.'},
  'diet.plan.dash.how': {'en': 'Plenty of vegetables, fruit, low-fat dairy and whole grains, with salt limited to about 5 g a day and less red meat and sugary drinks. Designed to lower blood pressure.', 'ru': 'Много овощей, фруктов, нежирных молочных и цельных злаков; соль до ~5 г в день, меньше красного мяса и сладких напитков. Создана для снижения давления.', 'uk': 'Багато овочів, фруктів, нежирних молочних і цільних злаків; сіль до ~5 г на день, менше червоного м’яса й солодких напоїв. Створена для зниження тиску.'},
  'diet.plan.dash.pro1': {'en': 'Lowers blood pressure.', 'ru': 'Снижает артериальное давление.', 'uk': 'Знижує артеріальний тиск.'},
  'diet.plan.dash.pro2': {'en': 'Well balanced in nutrients.', 'ru': 'Сбалансирована по нутриентам.', 'uk': 'Збалансована за нутрієнтами.'},
  'diet.plan.dash.pro3': {'en': 'Suitable for the whole family.', 'ru': 'Подходит для всей семьи.', 'uk': 'Підходить для всієї родини.'},
  'diet.plan.dash.con1': {'en': 'Needs home cooking and reading salt labels.', 'ru': 'Нужно готовить дома и читать этикетки на соль.', 'uk': 'Потрібно готувати вдома й читати етикетки на сіль.'},
  'diet.plan.dash.con2': {'en': 'Less salty taste — takes getting used to.', 'ru': 'Менее солёный вкус — нужно привыкнуть.', 'uk': 'Менш солоний смак — треба звикнути.'},
  'diet.plan.dash.con3': {'en': 'Not specifically aimed at weight loss.', 'ru': 'Не заточена специально под похудение.', 'uk': 'Не націлена спеціально на схуднення.'},
  'diet.plan.balanced.how': {'en': 'The plate rule: half vegetables, a quarter protein, a quarter whole-grain carbs. Nothing is banned — portions and regularity are what matter.', 'ru': 'Правило тарелки: половина — овощи, четверть — белок, четверть — цельные углеводы. Ничего не запрещено, важны порции и регулярность.', 'uk': 'Правило тарілки: половина — овочі, чверть — білок, чверть — цільні вуглеводи. Нічого не заборонено, важливі порції та регулярність.'},
  'diet.plan.balanced.pro1': {'en': 'Simple and flexible, no bans.', 'ru': 'Просто и гибко, без запретов.', 'uk': 'Просто й гнучко, без заборон.'},
  'diet.plan.balanced.pro2': {'en': 'Fits any goal — lose, maintain or gain.', 'ru': 'Подходит любой цели — похудеть, поддержать, набрать.', 'uk': 'Підходить будь-якій меті — схуднути, підтримати, набрати.'},
  'diet.plan.balanced.pro3': {'en': 'Easy to eyeball, no strict counting.', 'ru': 'Легко считать «на глаз», без строгого подсчёта.', 'uk': 'Легко рахувати «на око», без суворого підрахунку.'},
  'diet.plan.balanced.con1': {'en': 'Needs some portion discipline.', 'ru': 'Нужна дисциплина с порциями.', 'uk': 'Потрібна дисципліна з порціями.'},
  'diet.plan.balanced.con2': {'en': 'No fast "wow" result.', 'ru': 'Нет быстрого «вау»-результата.', 'uk': 'Немає швидкого «вау»-результату.'},
  'diet.plan.balanced.con3': {'en': 'Takes a little meal planning.', 'ru': 'Требует немного планирования еды.', 'uk': 'Потребує трохи планування їжі.'},
  'diet.plan.highProtein.how': {'en': 'A higher share of protein (~1.6-2.2 g/kg): meat, fish, eggs, cottage cheese and legumes at every meal. Preserves muscle in a deficit and builds it on a surplus.', 'ru': 'Повышенная доля белка (~1.6–2.2 г/кг): мясо, рыба, яйца, творог, бобовые в каждый приём. Сохраняет мышцы при дефиците и строит их при наборе.', 'uk': 'Підвищена частка білка (~1.6–2.2 г/кг): м’ясо, риба, яйця, сир, бобові в кожен прийом. Зберігає м’язи при дефіциті й будує їх при наборі.'},
  'diet.plan.highProtein.pro1': {'en': 'Keeps you full longer, fewer snacks.', 'ru': 'Дольше сытость, меньше перекусов.', 'uk': 'Довше ситість, менше перекусів.'},
  'diet.plan.highProtein.pro2': {'en': 'Preserves muscle while losing fat.', 'ru': 'Сохраняет мышцы при похудении.', 'uk': 'Зберігає м’язи при схудненні.'},
  'diet.plan.highProtein.pro3': {'en': 'Supports building muscle.', 'ru': 'Поддерживает набор мышечной массы.', 'uk': 'Підтримує набір м’язової маси.'},
  'diet.plan.highProtein.con1': {'en': 'Can be more expensive.', 'ru': 'Может быть дороже.', 'uk': 'Може бути дорожче.'},
  'diet.plan.highProtein.con2': {'en': 'Needs enough water and fibre alongside.', 'ru': 'Важно пить достаточно воды и есть клетчатку.', 'uk': 'Важливо пити достатньо води та їсти клітковину.'},
  'diet.plan.highProtein.con3': {'en': 'Not for kidney conditions without a doctor.', 'ru': 'Не подходит при болезнях почек без консультации врача.', 'uk': 'Не підходить при хворобах нирок без консультації лікаря.'},
  'diet.plan.lowCarb.how': {'en': 'Fewer fast carbs and sugar (white bread, sweets, soda), more protein, vegetables and healthy fats. Carbs come mainly from vegetables and whole grains.', 'ru': 'Меньше быстрых углеводов и сахара (белый хлеб, сладкое, газировка), больше белка, овощей и полезных жиров. Углеводы — из овощей и цельных круп.', 'uk': 'Менше швидких вуглеводів і цукру (білий хліб, солодке, газованка), більше білка, овочів і корисних жирів. Вуглеводи — з овочів і цільних круп.'},
  'diet.plan.lowCarb.pro1': {'en': 'Often a fast start to weight loss.', 'ru': 'Часто быстрый старт по снижению веса.', 'uk': 'Часто швидкий старт зі зниження ваги.'},
  'diet.plan.lowCarb.pro2': {'en': 'Steadier blood sugar and appetite.', 'ru': 'Стабильнее уровень сахара и аппетит.', 'uk': 'Стабільніший рівень цукру й апетит.'},
  'diet.plan.lowCarb.pro3': {'en': 'Cuts out "empty" calories.', 'ru': 'Убирает «пустые» калории.', 'uk': 'Прибирає «порожні» калорії.'},
  'diet.plan.lowCarb.con1': {'en': 'First days can bring low energy ("carb flu").', 'ru': 'Первые дни возможна слабость («углеводный грипп»).', 'uk': 'Перші дні можлива слабкість («вуглеводний грип»).'},
  'diet.plan.lowCarb.con2': {'en': 'Hard for endurance training.', 'ru': 'Трудно на тренировках на выносливость.', 'uk': 'Важко на тренуваннях на витривалість.'},
  'diet.plan.lowCarb.con3': {'en': 'Easy to overdo the fats.', 'ru': 'Легко переборщить с жирами.', 'uk': 'Легко переборщити з жирами.'},
  'diet.plan.fasting.how': {'en': 'Eat within an 8-hour window (e.g. 12:00-20:00) and fast for 16 (water, tea, black coffee are fine). Fewer meals simplify calorie control.', 'ru': 'Есть в 8-часовом окне (например 12:00–20:00), 16 часов — перерыв (вода, чай, чёрный кофе можно). Меньше приёмов — проще контроль калорий.', 'uk': 'Їсти у 8-годинному вікні (наприклад 12:00–20:00), 16 годин — перерва (вода, чай, чорна кава можна). Менше прийомів — простіший контроль калорій.'},
  'diet.plan.fasting.pro1': {'en': 'Simple rules, less counting.', 'ru': 'Простые правила, меньше подсчётов.', 'uk': 'Прості правила, менше підрахунків.'},
  'diet.plan.fasting.pro2': {'en': 'May improve insulin sensitivity.', 'ru': 'Может улучшить чувствительность к инсулину.', 'uk': 'Може покращити чутливість до інсуліну.'},
  'diet.plan.fasting.pro3': {'en': 'Convenient if you skip breakfast anyway.', 'ru': 'Удобно тем, кто и так не завтракает.', 'uk': 'Зручно тим, хто й так не снідає.'},
  'diet.plan.fasting.con1': {'en': 'Hunger and irritability at the start.', 'ru': 'Голод и раздражительность в начале.', 'uk': 'Голод і дратівливість на початку.'},
  'diet.plan.fasting.con2': {'en': 'Not for diabetes/pregnancy without a doctor.', 'ru': 'Не подходит при диабете/беременности без врача.', 'uk': 'Не підходить при діабеті/вагітності без лікаря.'},
  'diet.plan.fasting.con3': {'en': 'Risk of overeating in the window.', 'ru': 'Риск переесть в окне питания.', 'uk': 'Ризик переїсти у вікні харчування.'},
