  'wo.kbDeadlift.s1': {'en': 'Kettlebell between the feet, back flat, chest up.', 'ru': 'Гиря между стоп, спина прямая, грудь вперёд.', 'uk': 'Гиря між стоп, спина пряма, груди вперед.'},
